/**
 * 密码安全增强迁移
 * 添加密码历史记录、密码策略、登录尝试跟踪等表
 */

exports.up = function(knex) {
  return Promise.all([
    // 1. 添加用户表的密码安全字段
    knex.schema.table('users', function(table) {
      table.timestamp('password_changed_at').defaultTo(knex.fn.now()).comment('密码最后更改时间');
      table.boolean('password_expired').defaultTo(false).comment('密码是否已过期');
      table.boolean('force_password_change').defaultTo(false).comment('是否强制更改密码');
      table.integer('failed_login_attempts').defaultTo(0).comment('失败登录尝试次数');
      table.timestamp('locked_until').nullable().comment('账户锁定到期时间');
      table.timestamp('last_login_at').nullable().comment('最后登录时间');
      table.string('last_login_ip', 45).nullable().comment('最后登录IP地址');
    }),

    // 2. 创建密码历史记录表
    knex.schema.createTable('password_history', function(table) {
      table.increments('id').primary().comment('主键ID');
      table.integer('user_id').unsigned().notNullable().comment('用户ID');
      table.string('password_hash', 255).notNullable().comment('密码哈希值');
      table.timestamp('created_at').defaultTo(knex.fn.now()).comment('创建时间');
      table.string('created_by_ip', 45).nullable().comment('创建时的IP地址');

      // 外键约束
      table.foreign('user_id').references('id').inTable('users').onDelete('CASCADE');

      // 索引
      table.index(['user_id', 'created_at'], 'idx_password_history_user_time');
    }),

    // 3. 创建登录尝试记录表
    knex.schema.createTable('login_attempts', function(table) {
      table.increments('id').primary().comment('主键ID');
      table.string('email', 255).notNullable().comment('尝试登录的邮箱');
      table.string('ip_address', 45).notNullable().comment('IP地址');
      table.string('user_agent', 500).nullable().comment('用户代理');
      table.boolean('success').notNullable().comment('是否成功');
      table.string('failure_reason', 100).nullable().comment('失败原因');
      table.timestamp('attempted_at').defaultTo(knex.fn.now()).comment('尝试时间');
      table.json('additional_data').nullable().comment('额外数据');

      // 索引
      table.index(['email', 'attempted_at'], 'idx_login_attempts_email_time');
      table.index(['ip_address', 'attempted_at'], 'idx_login_attempts_ip_time');
      table.index(['success', 'attempted_at'], 'idx_login_attempts_success_time');
    }),

    // 4. 创建密码策略配置表
    knex.schema.createTable('password_policies', function(table) {
      table.increments('id').primary().comment('主键ID');
      table.string('name', 100).notNullable().unique().comment('策略名称');
      table.json('config').notNullable().comment('策略配置JSON');
      table.boolean('is_active').defaultTo(true).comment('是否激活');
      table.string('description', 500).nullable().comment('策略描述');
      table.timestamp('created_at').defaultTo(knex.fn.now()).comment('创建时间');
      table.timestamp('updated_at').defaultTo(knex.fn.now()).comment('更新时间');
      table.string('created_by', 100).nullable().comment('创建者');

      // 索引
      table.index(['is_active'], 'idx_password_policies_active');
    }),

    // 5. 创建安全事件日志表
    knex.schema.createTable('security_events', function(table) {
      table.increments('id').primary().comment('主键ID');
      table.integer('user_id').unsigned().nullable().comment('用户ID');
      table.string('event_type', 50).notNullable().comment('事件类型');
      table.string('event_description', 500).notNullable().comment('事件描述');
      table.string('ip_address', 45).nullable().comment('IP地址');
      table.string('user_agent', 500).nullable().comment('用户代理');
      table.enum('severity', ['low', 'medium', 'high', 'critical']).defaultTo('medium').comment('严重程度');
      table.json('event_data').nullable().comment('事件数据');
      table.timestamp('occurred_at').defaultTo(knex.fn.now()).comment('发生时间');
      table.boolean('resolved').defaultTo(false).comment('是否已解决');
      table.timestamp('resolved_at').nullable().comment('解决时间');
      table.string('resolved_by', 100).nullable().comment('解决者');

      // 外键约束
      table.foreign('user_id').references('id').inTable('users').onDelete('SET NULL');

      // 索引
      table.index(['event_type', 'occurred_at'], 'idx_security_events_type_time');
      table.index(['user_id', 'occurred_at'], 'idx_security_events_user_time');
      table.index(['severity', 'resolved'], 'idx_security_events_severity_resolved');
    })
  ]);
};

exports.down = function(knex) {
  return Promise.all([
    // 删除新创建的表
    knex.schema.dropTableIfExists('security_events'),
    knex.schema.dropTableIfExists('password_policies'),
    knex.schema.dropTableIfExists('login_attempts'),
    knex.schema.dropTableIfExists('password_history'),

    // 移除用户表的新字段
    knex.schema.table('users', function(table) {
      table.dropColumn('password_changed_at');
      table.dropColumn('password_expired');
      table.dropColumn('force_password_change');
      table.dropColumn('failed_login_attempts');
      table.dropColumn('locked_until');
      table.dropColumn('last_login_at');
      table.dropColumn('last_login_ip');
    })
  ]);
};

/**
 * 数据库初始化脚本
 * 运行迁移、创建索引、初始化数据
 */

const path = require('path');
const { db, testConnection, closeConnection } = require('../src/config/database');
const { logger } = require('../src/config/logger');
const { indexManager } = require('../src/utils/IndexManager');

class DatabaseInitializer {
  constructor() {
    this.options = {
      runMigrations: !process.argv.includes('--skip-migrations'),
      createIndexes: !process.argv.includes('--skip-indexes'),
      seedData: process.argv.includes('--seed'),
      force: process.argv.includes('--force'),
      verbose: process.argv.includes('--verbose')
    };
  }

  /**
   * 执行数据库初始化
   */
  async run() {
    try {
      logger.info('开始数据库初始化', this.options);

      // 测试数据库连接
      await this.testConnection();

      // 运行迁移
      if (this.options.runMigrations) {
        await this.runMigrations();
      }

      // 创建索引
      if (this.options.createIndexes) {
        await this.createIndexes();
      }

      // 种子数据
      if (this.options.seedData) {
        await this.seedData();
      }

      // 验证数据库状态
      await this.validateDatabase();

      logger.info('数据库初始化完成');

    } catch (error) {
      logger.error('数据库初始化失败', { error: error.message });
      throw error;
    } finally {
      await closeConnection();
    }
  }

  /**
   * 测试数据库连接
   */
  async testConnection() {
    logger.info('测试数据库连接...');

    try {
      await testConnection();
      logger.info('数据库连接成功');
    } catch (error) {
      logger.error('数据库连接失败', { error: error.message });
      throw error;
    }
  }

  /**
   * 运行数据库迁移
   */
  async runMigrations() {
    logger.info('运行数据库迁移...');

    try {
      // 使用Knex运行迁移
      const [batchNo, migrations] = await db.migrate.latest();

      if (migrations.length === 0) {
        logger.info('没有需要运行的迁移');
      } else {
        logger.info('迁移运行完成', { 
          batchNo, 
          migrations: migrations.map(m => path.basename(m))
        });
      }
    } catch (error) {
      logger.error('运行迁移失败', { error: error.message });
      throw error;
    }
  }

  /**
   * 创建数据库索引
   */
  async createIndexes() {
    logger.info('创建数据库索引...');

    try {
      const results = await indexManager.createAllIndexes({
        force: this.options.force,
        parallel: false, // 串行创建更安全
        skipExisting: !this.options.force
      });

      if (results.failed.length > 0) {
        logger.warn('部分索引创建失败', { failed: results.failed });
      }

      logger.info('索引创建完成', {
        created: results.created.length,
        skipped: results.skipped.length,
        failed: results.failed.length
      });

      if (this.options.verbose) {
        logger.info('索引创建详情', results);
      }
    } catch (error) {
      logger.error('创建索引失败', { error: error.message });
      throw error;
    }
  }

  /**
   * 运行种子数据
   */
  async seedData() {
    logger.info('运行种子数据...');

    try {
      const [seedFiles] = await db.seed.run();

      if (seedFiles.length === 0) {
        logger.info('没有种子文件需要运行');
      } else {
        logger.info('种子数据运行完成', { 
          files: seedFiles.map(f => path.basename(f))
        });
      }
    } catch (error) {
      logger.error('运行种子数据失败', { error: error.message });
      throw error;
    }
  }

  /**
   * 验证数据库状态
   */
  async validateDatabase() {
    logger.info('验证数据库状态...');

    try {
      // 检查表是否存在
      const tables = await this.checkTables();

      // 验证索引
      const indexValidation = await indexManager.validateIndexes();

      // 检查数据完整性
      const dataIntegrity = await this.checkDataIntegrity();

      const validation = {
        tables,
        indexes: indexValidation,
        dataIntegrity
      };

      if (this.options.verbose) {
        logger.info('数据库验证详情', validation);
      }

      // 检查是否有严重问题
      const hasIssues = indexValidation.invalid.length > 0 || 
                       indexValidation.missing.length > 0 ||
                       !dataIntegrity.valid;

      if (hasIssues) {
        logger.warn('数据库验证发现问题', validation);
      } else {
        logger.info('数据库验证通过');
      }

      return validation;
    } catch (error) {
      logger.error('数据库验证失败', { error: error.message });
      throw error;
    }
  }

  /**
   * 检查必需的表是否存在
   */
  async checkTables() {
    const requiredTables = [
      'users',
      'orders', 
      'quotes',
      'providers',
      'order_sequences'
    ];

    const results = {
      existing: [],
      missing: []
    };

    for (const table of requiredTables) {
      const exists = await db.schema.hasTable(table);
      if (exists) {
        results.existing.push(table);
      } else {
        results.missing.push(table);
      }
    }

    if (results.missing.length > 0) {
      logger.warn('缺少必需的表', { missing: results.missing });
    }

    return results;
  }

  /**
   * 检查数据完整性
   */
  async checkDataIntegrity() {
    try {
      // 检查外键约束
      await db.raw('PRAGMA foreign_key_check');

      // 检查序列表是否有今天的记录
      const today = new Date().toISOString().slice(0, 10).replace(/-/g, '');
      const todaySequence = await db('order_sequences')
        .where('date', today)
        .first();

      return {
        valid: true,
        foreignKeyCheck: 'passed',
        sequenceTable: todaySequence ? 'initialized' : 'empty'
      };
    } catch (error) {
      logger.error('数据完整性检查失败', { error: error.message });
      return {
        valid: false,
        error: error.message
      };
    }
  }

  /**
   * 获取数据库统计信息
   */
  async getDatabaseStats() {
    try {
      const stats = {};

      // 表统计
      const tables = ['users', 'orders', 'quotes', 'providers', 'order_sequences'];
      for (const table of tables) {
        try {
          const count = await db(table).count('* as count').first();
          stats[table] = parseInt(count.count, 10);
        } catch (error) {
          stats[table] = 'error';
        }
      }

      // 索引统计
      const indexStats = await indexManager.getIndexStats();
      stats.indexes = indexStats;

      return stats;
    } catch (error) {
      logger.error('获取数据库统计信息失败', { error: error.message });
      return { error: error.message };
    }
  }
}

// 主函数
async function main() {
  const initializer = new DatabaseInitializer();

  try {
    await initializer.run();

    // 显示统计信息
    if (initializer.options.verbose) {
      const stats = await initializer.getDatabaseStats();
      console.log('\n=== 数据库统计信息 ===');
      console.log(JSON.stringify(stats, null, 2));
      console.log('=====================\n');
    }

    process.exit(0);
  } catch (error) {
    console.error('初始化失败:', error.message);
    process.exit(1);
  }
}

// 如果直接运行此脚本
if (require.main === module) {
  // 显示使用说明
  if (process.argv.includes('--help')) {
    console.log(`
使用方法: node initDatabase.js [选项]

选项:
  --skip-migrations    跳过数据库迁移
  --skip-indexes       跳过索引创建
  --seed              运行种子数据
  --force             强制重新创建索引
  --verbose           显示详细信息
  --help              显示此帮助信息

示例:
  node initDatabase.js --verbose
  node initDatabase.js --seed --force
  node initDatabase.js --skip-migrations --skip-indexes
    `);
    process.exit(0);
  }

  main();
}

module.exports = DatabaseInitializer;

/**
 * ESLint配置验证脚本
 * 验证前后端ESLint配置是否正确工作
 */

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

class ESLintConfigValidator {
  constructor() {
    this.projectRoot = process.cwd();
    this.results = {
      backend: { passed: 0, failed: 0, errors: [] },
      frontend: { passed: 0, failed: 0, errors: [] }
    };
  }

  /**
   * 运行验证
   */
  async run() {
    console.log('🔍 开始验证ESLint配置...\n');

    try {
      await this.validateBackendConfig();
      await this.validateFrontendConfig();
      await this.validateCrossProjectConsistency();

      this.printResults();

      const totalErrors = this.results.backend.failed + this.results.frontend.failed;
      if (totalErrors > 0) {
        process.exit(1);
      }

      console.log('✅ ESLint配置验证通过！');
    } catch (error) {
      console.error('❌ ESLint配置验证失败:', error.message);
      process.exit(1);
    }
  }

  /**
   * 验证后端配置
   */
  async validateBackendConfig() {
    console.log('📋 验证后端ESLint配置...');

    const tests = [
      {
        name: '后端配置文件存在',
        test: () => fs.existsSync(path.join(this.projectRoot, '.eslintrc.js'))
      },
      {
        name: '后端代码语法检查',
        test: () => this.runESLint('src/', '--ext .js')
      },
      {
        name: '测试文件语法检查',
        test: () => this.runESLint('tests/', '--ext .js')
      },
      {
        name: '复杂度规则生效',
        test: () => this.checkComplexityRule('src/')
      },
      {
        name: '异步编程规则生效',
        test: () => this.checkAsyncRules('src/')
      }
    ];

    for (const test of tests) {
      try {
        const result = await test.test();
        if (result !== false) {
          this.results.backend.passed++;
          console.log(`  ✅ ${test.name}`);
        } else {
          this.results.backend.failed++;
          console.log(`  ❌ ${test.name}`);
        }
      } catch (error) {
        this.results.backend.failed++;
        this.results.backend.errors.push(`${test.name}: ${error.message}`);
        console.log(`  ❌ ${test.name}: ${error.message}`);
      }
    }
  }

  /**
   * 验证前端配置
   */
  async validateFrontendConfig() {
    console.log('\n📋 验证前端ESLint配置...');

    const frontendPath = path.join(this.projectRoot, 'frontend');
    if (!fs.existsSync(frontendPath)) {
      console.log('  ⚠️  前端目录不存在，跳过前端验证');
      return;
    }

    const tests = [
      {
        name: '前端配置文件存在',
        test: () => fs.existsSync(path.join(frontendPath, '.eslintrc.js'))
      },
      {
        name: '前端代码语法检查',
        test: () => this.runESLint('frontend/src/', '--ext .js,.jsx,.ts,.tsx')
      },
      {
        name: 'React规则生效',
        test: () => this.checkReactRules('frontend/src/')
      },
      {
        name: 'TypeScript规则生效',
        test: () => this.checkTypeScriptRules('frontend/src/')
      },
      {
        name: '可访问性规则生效',
        test: () => this.checkA11yRules('frontend/src/')
      }
    ];

    for (const test of tests) {
      try {
        const result = await test.test();
        if (result !== false) {
          this.results.frontend.passed++;
          console.log(`  ✅ ${test.name}`);
        } else {
          this.results.frontend.failed++;
          console.log(`  ❌ ${test.name}`);
        }
      } catch (error) {
        this.results.frontend.failed++;
        this.results.frontend.errors.push(`${test.name}: ${error.message}`);
        console.log(`  ❌ ${test.name}: ${error.message}`);
      }
    }
  }

  /**
   * 验证跨项目一致性
   */
  async validateCrossProjectConsistency() {
    console.log('\n📋 验证跨项目配置一致性...');

    const tests = [
      {
        name: '代码质量标准一致',
        test: () => this.checkQualityStandardsConsistency()
      },
      {
        name: '复杂度限制一致',
        test: () => this.checkComplexityConsistency()
      },
      {
        name: '安全规则一致',
        test: () => this.checkSecurityRulesConsistency()
      }
    ];

    for (const test of tests) {
      try {
        const result = await test.test();
        if (result !== false) {
          console.log(`  ✅ ${test.name}`);
        } else {
          console.log(`  ❌ ${test.name}`);
        }
      } catch (error) {
        console.log(`  ❌ ${test.name}: ${error.message}`);
      }
    }
  }

  /**
   * 运行ESLint检查
   */
  runESLint(path, extensions) {
    try {
      execSync(`npx eslint ${path} ${extensions} --quiet`, { 
        stdio: 'pipe',
        cwd: this.projectRoot 
      });
      return true;
    } catch (error) {
      // ESLint返回非零退出码表示有错误，但这里我们只是验证配置是否工作
      return error.status !== 2; // 2表示配置错误
    }
  }

  /**
   * 检查复杂度规则
   */
  checkComplexityRule(path) {
    try {
      const output = execSync(`npx eslint ${path} --ext .js --format json`, { 
        stdio: 'pipe',
        cwd: this.projectRoot 
      });

      const results = JSON.parse(output.toString());
      results.some(result =>
        result.messages.some(message => message.ruleId === 'complexity')
      );

      return true; // 配置存在即可
    } catch (error) {
      return error.status !== 2;
    }
  }

  /**
   * 检查异步编程规则
   */
  checkAsyncRules(path) {
    const asyncRules = ['require-await', 'no-async-promise-executor', 'prefer-promise-reject-errors'];
    // 简化检查：只要配置文件包含这些规则就认为通过
    const configPath = path.includes('frontend') ? 
      'frontend/.eslintrc.js' : '.eslintrc.js';

    try {
      const config = fs.readFileSync(configPath, 'utf8');
      return asyncRules.some(rule => config.includes(rule));
    } catch (error) {
      return false;
    }
  }

  /**
   * 检查React规则
   */
  checkReactRules(_path) {
    try {
      const configPath = 'frontend/.eslintrc.js';
      const config = fs.readFileSync(configPath, 'utf8');
      return config.includes('react-hooks/rules-of-hooks');
    } catch (error) {
      return false;
    }
  }

  /**
   * 检查TypeScript规则
   */
  checkTypeScriptRules(_path) {
    try {
      const configPath = 'frontend/.eslintrc.js';
      const config = fs.readFileSync(configPath, 'utf8');
      return config.includes('@typescript-eslint');
    } catch (error) {
      return false;
    }
  }

  /**
   * 检查可访问性规则
   */
  checkA11yRules(_path) {
    try {
      const configPath = 'frontend/.eslintrc.js';
      const config = fs.readFileSync(configPath, 'utf8');
      return config.includes('jsx-a11y');
    } catch (error) {
      return false;
    }
  }

  /**
   * 检查质量标准一致性
   */
  checkQualityStandardsConsistency() {
    // 检查前后端都有相同的基础质量规则
    const commonRules = ['no-console', 'no-debugger', 'prefer-const', 'complexity'];

    try {
      const backendConfig = fs.readFileSync('.eslintrc.js', 'utf8');
      const frontendConfig = fs.readFileSync('frontend/.eslintrc.js', 'utf8');

      return commonRules.every(rule => 
        backendConfig.includes(rule) && frontendConfig.includes(rule)
      );
    } catch (error) {
      return false;
    }
  }

  /**
   * 检查复杂度限制一致性
   */
  checkComplexityConsistency() {
    try {
      const backendConfig = fs.readFileSync('.eslintrc.js', 'utf8');
      const frontendConfig = fs.readFileSync('frontend/.eslintrc.js', 'utf8');

      const backendComplexity = backendConfig.match(/complexity.*?(\d+)/);
      const frontendComplexity = frontendConfig.match(/complexity.*?(\d+)/);

      return backendComplexity && frontendComplexity && 
             backendComplexity[1] === frontendComplexity[1];
    } catch (error) {
      return false;
    }
  }

  /**
   * 检查安全规则一致性
   */
  checkSecurityRulesConsistency() {
    const securityRules = ['no-eval', 'no-implied-eval', 'no-new-func'];

    try {
      const backendConfig = fs.readFileSync('.eslintrc.js', 'utf8');
      const frontendConfig = fs.readFileSync('frontend/.eslintrc.js', 'utf8');

      return securityRules.every(rule => 
        backendConfig.includes(rule) && frontendConfig.includes(rule)
      );
    } catch (error) {
      return false;
    }
  }

  /**
   * 打印验证结果
   */
  printResults() {
    console.log('\n📊 验证结果汇总:');
    console.log(`后端: ${this.results.backend.passed} 通过, ${this.results.backend.failed} 失败`);
    console.log(`前端: ${this.results.frontend.passed} 通过, ${this.results.frontend.failed} 失败`);

    if (this.results.backend.errors.length > 0) {
      console.log('\n❌ 后端错误:');
      this.results.backend.errors.forEach(error => console.log(`  - ${error}`));
    }

    if (this.results.frontend.errors.length > 0) {
      console.log('\n❌ 前端错误:');
      this.results.frontend.errors.forEach(error => console.log(`  - ${error}`));
    }
  }
}

