/**
 * 物流报价对比系统 - 主应用文件
 * 重构版本 - 采用分层架构设计
 */

const express = require('express');
const cors = require('cors');
const { logger } = require('./config/logger');
const config = require('./config/env');
const { security, errorHandler, initializeErrorHandling } = require('./middleware');
const routes = require('./routes');

// 初始化全局错误处理
initializeErrorHandling();

// 创建Express应用
const app = express();

// 信任代理设置（用于获取真实IP）
app.set('trust proxy', true);

// 基础中间件
app.use(security.securityHeaders); // 安全头
app.use(cors()); // CORS支持
app.use(express.json({ limit: '10mb' })); // JSON解析
app.use(express.urlencoded({ extended: true, limit: '10mb' })); // URL编码解析

// 请求日志中间件
app.use(security.requestLogger);

// 只在非测试环境启用限流
if (process.env.NODE_ENV !== 'test') {
  app.use('/api/', security.apiRateLimit);
}

// 健康检查端点
app.get('/health', (req, res) => {
  res.json({
    success: true,
    message: 'Service is healthy',
    timestamp: new Date().toISOString(),
    version: process.env.npm_package_version || '3.0.0',
    environment: config.app.env
  });
});

// API路由
app.use('/api', routes);

// 404处理
app.use('*', (req, res) => {
  res.status(404).json({
    success: false,
    message: '接口不存在'
  });
});

// 错误处理中间件
app.use(errorHandler);

// 启动服务器 - 只在非测试环境自动启动
const PORT = config.app.port;
let server;

if (process.env.NODE_ENV !== 'test') {
  server = app.listen(PORT, config.app.host, () => {
    logger.info(`WLBJ服务器启动成功`, {
      port: PORT,
      host: config.app.host,
      environment: config.app.env,
      timestamp: new Date().toISOString()
    });
  });

  // 优雅关闭处理
  const gracefulShutdown = (signal) => {
    logger.info(`收到${signal}信号，开始优雅关闭服务器`);

    server.close(() => {
      logger.info('HTTP服务器已关闭');
      process.exit(0);
    });

    // 强制关闭超时
    setTimeout(() => {
      logger.error('强制关闭服务器');
      process.exit(1);
    }, 10000);
  };

  process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
  process.on('SIGINT', () => gracefulShutdown('SIGINT'));
}

// 提供服务器关闭方法
app.closeServer = () => {
  if (server) {
    return new Promise((resolve) => {
      server.close(() => {
        logger.info('服务器已关闭');
        resolve();
      });
    });
  }
  return Promise.resolve();
};

module.exports = app;

const knex = require('knex');
const knexConfig = require('../../knexfile');
const logger = require('./logger');

const environment = process.env.NODE_ENV || 'development';
const config = knexConfig[environment];

// 创建数据库连接
const db = knex(config);

// 数据库连接测试
async function testConnection() {
  try {
    await db.raw('SELECT 1');
    logger.info('数据库连接成功', { environment });
    return true;
  } catch (error) {
    logger.error('数据库连接失败', { error: error.message, environment });
    throw error;
  }
}

// 优雅关闭数据库连接
async function closeConnection() {
  try {
    await db.destroy();
    logger.info('数据库连接已关闭');
  } catch (error) {
    logger.error('关闭数据库连接失败', { error: error.message });
    throw error;
  }
}

// 事务管理器
class TransactionManager {
  async executeTransaction(callback) {
    const trx = await db.transaction();

    try {
      const result = await callback(trx);
      await trx.commit();
      return result;
    } catch (error) {
      await trx.rollback();
      throw error;
    }
  }

  async executeWithRetry(callback, maxRetries = 3) {
    let lastError;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        return await this.executeTransaction(callback);
      } catch (error) {
        lastError = error;

        // 如果是数据库锁定错误，等待后重试
        if (error.code === 'SQLITE_BUSY' && attempt < maxRetries) {
          const delay = Math.min(1000 * Math.pow(2, attempt - 1), 5000);
          await new Promise(resolve => setTimeout(resolve, delay));
          continue;
        }

        throw error;
      }
    }

    throw lastError;
  }
}

const transactionManager = new TransactionManager();

module.exports = {
  db,
  testConnection,
  closeConnection,
  transactionManager,
};

/**
 * 基础Controller类
 * 提供通用的请求处理和响应格式化方法
 */

const { logger } = require('../config/logger');

class BaseController {
  constructor(name) {
    this.controllerName = name;
  }

  /**
   * 处理异步请求
   * @param {Function} handler - 处理函数
   * @returns {Function} Express中间件函数
   */
  asyncHandler(handler) {
    return async (req, res, next) => {
      try {
        await handler(req, res, next);
      } catch (error) {
        this.handleError(error, req, res, next);
      }
    };
  }

  /**
   * 统一错误处理 - 委托给全局错误处理中间件
   * @param {Error} error - 错误对象
   * @param {Object} req - Express请求对象
   * @param {Object} res - Express响应对象
   * @param {Function} next - Express next函数
   */
  handleError(error, req, res, next) {
    // 添加控制器上下文信息
    error.controller = this.controllerName;

    // 记录控制器级别的错误日志
    logger.error(`${this.controllerName} 控制器错误`, {
      error: error.message,
      code: error.code,
      method: req.method,
      url: req.url,
      userId: req.user?.id
    });

    // 委托给全局错误处理中间件
    next(error);
  }

  /**
   * 发送成功响应
   * @param {Object} res - Express响应对象
   * @param {any} data - 响应数据
   * @param {string} message - 响应消息
   * @param {number} statusCode - HTTP状态码
   * @param {Object} meta - 元数据
   */
  sendSuccess(res, data, message = 'success', statusCode = 200, meta = {}) {
    const response = {
      success: true,
      message,
      data,
      meta: {
        timestamp: new Date().toISOString(),
        ...meta
      }
    };

    res.status(statusCode).json(response);
  }

  /**
   * 发送分页响应
   * @param {Object} res - Express响应对象
   * @param {Array} items - 数据项
   * @param {number} total - 总数
   * @param {Object} pagination - 分页信息
   * @param {string} message - 响应消息
   */
  sendPaginatedResponse(res, items, total, pagination, message = 'success') {
    const { page, limit } = pagination;
    const totalPages = Math.ceil(total / limit);

    this.sendSuccess(res, items, message, 200, {
      pagination: {
        page,
        limit,
        total,
        totalPages,
        hasNext: page < totalPages,
        hasPrev: page > 1
      }
    });
  }

  /**
   * 发送错误响应
   * @param {Object} res - Express响应对象
   * @param {string} message - 错误消息
   * @param {number} statusCode - HTTP状态码
   * @param {string} code - 错误代码
   */
  sendError(res, message, statusCode = 400, code = 'BAD_REQUEST') {
    const response = {
      success: false,
      message,
      code,
      timestamp: new Date().toISOString()
    };

    res.status(statusCode).json(response);
  }

  /**
   * 验证必需参数
   * @param {Object} data - 数据对象
   * @param {Array} requiredFields - 必需字段数组
   * @throws {Error} 参数验证失败时抛出错误
   */
  validateRequiredParams(data, requiredFields) {
    const missingFields = [];

    for (const field of requiredFields) {
      if (data[field] === undefined || data[field] === null || data[field] === '') {
        missingFields.push(field);
      }
    }

    if (missingFields.length > 0) {
      const error = new Error(`缺少必需参数: ${missingFields.join(', ')}`);
      error.statusCode = 400;
      error.code = 'MISSING_REQUIRED_PARAMS';
      throw error;
    }
  }

  /**
   * 获取用户信息
   * @param {Object} req - Express请求对象
   * @returns {Object} 用户信息
   */
  getCurrentUser(req) {
    if (!req.user) {
      const error = new Error('用户未认证');
      error.statusCode = 401;
      error.code = 'UNAUTHORIZED';
      throw error;
    }
    return req.user;
  }

  /**
   * 检查用户权限
   * @param {Object} req - Express请求对象
   * @param {string|Array} requiredRoles - 必需的角色
   * @throws {Error} 权限不足时抛出错误
   */
  checkUserRole(req, requiredRoles) {
    const user = this.getCurrentUser(req);
    const roles = Array.isArray(requiredRoles) ? requiredRoles : [requiredRoles];

    if (!roles.includes(user.role)) {
      const error = new Error('权限不足');
      error.statusCode = 403;
      error.code = 'INSUFFICIENT_PERMISSIONS';
      throw error;
    }
  }

  /**
   * 提取分页参数
   * @param {Object} req - Express请求对象
   * @returns {Object} 分页参数
   */
  extractPaginationParams(req) {
    const page = parseInt(req.query.page, 10) || 1;
    const limit = parseInt(req.query.limit, 10) || 20;

    // 验证分页参数
    if (page < 1) {
      const error = new Error('页码必须大于0');
      error.statusCode = 400;
      error.code = 'INVALID_PAGE';
      throw error;
    }

    if (limit < 1 || limit > 100) {
      const error = new Error('每页数量必须在1-100之间');
      error.statusCode = 400;
      error.code = 'INVALID_LIMIT';
      throw error;
    }

    return {
      page,
      limit,
      offset: (page - 1) * limit
    };
  }

  /**
   * 提取排序参数
   * @param {Object} req - Express请求对象
   * @param {Array} allowedFields - 允许排序的字段
   * @returns {Array} 排序参数
   */
  extractSortParams(req, allowedFields = []) {
    const sortBy = req.query.sortBy;
    const sortOrder = req.query.sortOrder || 'asc';

    if (!sortBy) {
      return [];
    }

    // 验证排序字段
    if (allowedFields.length > 0 && !allowedFields.includes(sortBy)) {
      const error = new Error(`不允许按字段 '${sortBy}' 排序`);
      error.statusCode = 400;
      error.code = 'INVALID_SORT_FIELD';
      throw error;
    }

    // 验证排序方向
    if (!['asc', 'desc'].includes(sortOrder.toLowerCase())) {
      const error = new Error('排序方向必须是 asc 或 desc');
      error.statusCode = 400;
      error.code = 'INVALID_SORT_ORDER';
      throw error;
    }

    return [{
      column: sortBy,
      direction: sortOrder.toLowerCase()
    }];
  }

  /**
   * 提取过滤参数
   * @param {Object} req - Express请求对象
   * @param {Array} allowedFilters - 允许的过滤字段
   * @returns {Object} 过滤参数
   */
  extractFilterParams(req, allowedFilters = []) {
    const filters = {};

    for (const filter of allowedFilters) {
      if (req.query[filter] !== undefined) {
        filters[filter] = req.query[filter];
      }
    }

    return filters;
  }

  /**
   * 记录操作日志
   * @param {string} action - 操作名称
   * @param {Object} req - Express请求对象
   * @param {Object} data - 操作数据
   */
  logOperation(action, req, data = {}) {
    logger.info(`${this.controllerName} - ${action}`, {
      controller: this.controllerName,
      action,
      method: req.method,
      url: req.url,
      userId: req.user?.id,
      userRole: req.user?.role,
      ip: req.ip,
      userAgent: req.get('User-Agent'),
      ...data,
      timestamp: new Date().toISOString()
    });
  }

  /**
   * 清理敏感数据
   * @param {Object} data - 数据对象
   * @param {Array} sensitiveFields - 敏感字段数组
   * @returns {Object} 清理后的数据对象
   */
  sanitizeData(data, sensitiveFields = ['password', 'accessKey', 'secret']) {
    if (!data || typeof data !== 'object') {
      return data;
    }

    if (Array.isArray(data)) {
      return data.map(item => this.sanitizeData(item, sensitiveFields));
    }

    const sanitized = { ...data };

    for (const field of sensitiveFields) {
      if (sanitized[field] !== undefined) {
        delete sanitized[field];
      }
    }

    return sanitized;
  }

  /**
   * 验证请求体
   * @param {Object} req - Express请求对象
   * @param {Array} requiredFields - 必需字段
   * @returns {Object} 验证后的请求体
   */
  validateRequestBody(req, requiredFields = []) {
    if (!req.body || typeof req.body !== 'object') {
      const error = new Error('请求体不能为空');
      error.statusCode = 400;
      error.code = 'EMPTY_REQUEST_BODY';
      throw error;
    }

    this.validateRequiredParams(req.body, requiredFields);
    return req.body;
  }

  /**
   * 验证路径参数
   * @param {Object} req - Express请求对象
   * @param {Array} requiredParams - 必需参数
   * @returns {Object} 验证后的路径参数
   */
  validatePathParams(req, requiredParams = []) {
    this.validateRequiredParams(req.params, requiredParams);
    return req.params;
  }
}

module.exports = BaseController;

/**
 * 订单控制器
 * 处理订单相关的HTTP请求
 */

const BaseController = require('./BaseController');
const { orderService } = require('../services');

class OrderController extends BaseController {
  constructor() {
    super('OrderController');
    this.allowedSortFields = ['createdAt', 'updatedAt', 'status', 'selectedPrice'];
    this.allowedFilterFields = ['status', 'startDate', 'endDate'];
  }

  /**
   * 创建订单
   * POST /api/orders
   */
  createOrder = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const orderData = this.validateRequestBody(req, ['warehouse', 'goods', 'deliveryAddress']);

    this.logOperation('create_order_request', req, {
      warehouse: orderData.warehouse,
      userId: user.id
    });

    const result = await orderService.createOrder(orderData, user.id);

    this.sendSuccess(res, result.data, result.message, 201, result.meta);
  });

  /**
   * 获取订单详情
   * GET /api/orders/:orderId
   */
  getOrderById = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const { orderId } = this.validatePathParams(req, ['orderId']);

    this.logOperation('get_order_request', req, { orderId, userId: user.id });

    const result = await orderService.getOrderById(orderId, user.id, user.role);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 获取用户订单列表
   * GET /api/orders
   */
  getUserOrders = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);

    // 提取查询参数
    const pagination = this.extractPaginationParams(req);
    const orderBy = this.extractSortParams(req, this.allowedSortFields);
    const filters = this.extractFilterParams(req, this.allowedFilterFields);

    const options = {
      ...pagination,
      orderBy,
      ...filters
    };

    this.logOperation('get_user_orders_request', req, {
      userId: user.id,
      options
    });

    const result = await orderService.getUserOrders(user.id, options);

    if (result.data && Array.isArray(result.data)) {
      this.sendPaginatedResponse(res, result.data, result.meta.pagination.total, pagination, result.message);
    } else {
      this.sendSuccess(res, result.data, result.message, 200, result.meta);
    }
  });

  /**
   * 更新订单
   * PUT /api/orders/:orderId
   */
  updateOrder = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const { orderId } = this.validatePathParams(req, ['orderId']);
    const updateData = this.validateRequestBody(req);

    // 验证至少有一个可更新的字段
    const allowedFields = ['warehouse', 'goods', 'deliveryAddress'];
    const hasValidField = allowedFields.some(field => updateData[field] !== undefined);

    if (!hasValidField) {
      return this.sendError(res, '请提供至少一个可更新的字段', 400, 'NO_UPDATE_FIELDS');
    }

    this.logOperation('update_order_request', req, {
      orderId,
      userId: user.id,
      updateFields: Object.keys(updateData)
    });

    const result = await orderService.updateOrder(orderId, updateData, user.id, user.role);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 更新订单状态
   * PATCH /api/orders/:id/status
   */
  updateOrderStatus = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const { id: orderId } = this.validatePathParams(req, ['id']);
    const { status } = this.validateRequestBody(req, ['status']);

    this.logOperation('update_order_status_request', req, {
      orderId,
      status,
      userId: user.id
    });

    const result = await orderService.updateOrderStatus(orderId, status, user.id, user.role);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 删除订单
   * DELETE /api/orders/:id
   */
  deleteOrder = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const { id: orderId } = this.validatePathParams(req, ['id']);

    this.logOperation('delete_order_request', req, {
      orderId,
      userId: user.id
    });

    const result = await orderService.deleteOrder(orderId, user.id, user.role);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 选择供应商
   * POST /api/orders/:orderId/select-provider
   */
  selectProvider = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const { orderId } = this.validatePathParams(req, ['orderId']);
    const { provider } = this.validateRequestBody(req, ['provider']);

    this.logOperation('select_provider_request', req, {
      orderId,
      provider,
      userId: user.id
    });

    const result = await orderService.selectProvider(orderId, provider, user.id, user.role);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 取消订单
   * POST /api/orders/:orderId/cancel
   */
  cancelOrder = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const { orderId } = this.validatePathParams(req, ['orderId']);
    const { reason } = req.body || {};

    this.logOperation('cancel_order_request', req, {
      orderId,
      reason,
      userId: user.id
    });

    const result = await orderService.cancelOrder(orderId, reason, user.id, user.role);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 搜索订单
   * GET /api/orders/search
   */
  searchOrders = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const { q: searchTerm } = req.query;

    if (!searchTerm) {
      return this.sendError(res, '搜索关键词不能为空', 400, 'MISSING_SEARCH_TERM');
    }

    // 提取查询参数
    const pagination = this.extractPaginationParams(req);
    const filters = this.extractFilterParams(req, ['status']);

    const options = {
      ...pagination,
      ...filters
    };

    this.logOperation('search_orders_request', req, {
      searchTerm,
      userId: user.id,
      options
    });

    const result = await orderService.searchOrders(searchTerm, user.id, user.role, options);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 获取订单统计信息
   * GET /api/orders/stats
   */
  getOrderStats = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);

    // 提取过滤参数
    const filters = this.extractFilterParams(req, ['startDate', 'endDate']);

    this.logOperation('get_order_stats_request', req, {
      userId: user.id,
      userRole: user.role,
      filters
    });

    const result = await orderService.getOrderStats(user.id, user.role, filters);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 获取待处理订单列表（管理员功能）
   * GET /api/orders/pending
   */
  getPendingOrders = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    this.checkUserRole(req, 'admin');

    // 提取查询参数
    const pagination = this.extractPaginationParams(req);
    const orderBy = this.extractSortParams(req, this.allowedSortFields);

    const options = {
      ...pagination,
      orderBy
    };

    this.logOperation('get_pending_orders_request', req, {
      userId: user.id,
      options
    });

    const result = await orderService.getPendingOrders(options);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 批量操作订单（管理员功能）
   * POST /api/orders/batch
   */
  batchOperateOrders = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    this.checkUserRole(req, 'admin');

    const { orderIds, operation } = this.validateRequestBody(req, ['orderIds', 'operation']);

    if (!Array.isArray(orderIds) || orderIds.length === 0) {
      return this.sendError(res, '订单ID列表不能为空', 400, 'EMPTY_ORDER_IDS');
    }

    const validOperations = ['cancel', 'complete'];
    if (!validOperations.includes(operation)) {
      return this.sendError(res, '无效的批量操作类型', 400, 'INVALID_OPERATION');
    }

    this.logOperation('batch_operate_orders_request', req, {
      orderIds,
      operation,
      userId: user.id,
      count: orderIds.length
    });

    const result = await orderService.batchUpdateOrders(orderIds, operation, user.id);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 导出订单数据（管理员功能）
   * GET /api/orders/export
   */
  exportOrders = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    this.checkUserRole(req, 'admin');

    // 提取过滤参数
    const filters = this.extractFilterParams(req, ['status', 'startDate', 'endDate']);
    const format = req.query.format || 'csv';

    this.logOperation('export_orders_request', req, {
      userId: user.id,
      filters,
      format
    });

    const result = await orderService.exportOrders(filters, format);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 获取订单统计信息（管理员）
   * GET /api/orders/admin/stats
   */
  getOrderStats = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    this.checkUserRole(req, 'admin');

    this.logOperation('get_order_stats_request', req, {
      userId: user.id
    });

    const result = await orderService.getOrderStats();

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });
}

module.exports = OrderController;

/**
 * 报价控制器
 * 处理报价相关的HTTP请求
 */

const BaseController = require('./BaseController');
const { quoteService } = require('../services');

class QuoteController extends BaseController {
  constructor() {
    super('QuoteController');
    this.allowedSortFields = ['price', 'createdAt', 'estimatedDelivery'];
    this.allowedFilterFields = ['startDate', 'endDate'];
  }

  /**
   * 创建或更新报价（供应商接口）
   * POST /api/quotes/:orderId
   */
  createOrUpdateQuote = this.asyncHandler(async (req, res) => {
    const { orderId } = this.validatePathParams(req, ['orderId']);
    const quoteData = this.validateRequestBody(req, ['price', 'estimatedDelivery']);

    // 从请求头获取供应商信息
    const provider = req.headers['x-provider-name'];
    const accessKey = req.headers['x-access-key'];

    if (!provider || !accessKey) {
      return this.sendError(res, '缺少供应商认证信息', 401, 'MISSING_PROVIDER_AUTH');
    }

    this.logOperation('create_or_update_quote_request', req, {
      orderId,
      provider,
      price: quoteData.price
    });

    const result = await quoteService.createOrUpdateQuote(orderId, provider, quoteData, accessKey);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 提交报价（供应商接口）- submitQuote别名
   * POST /api/quotes/orders/:orderId
   */
  submitQuote = this.createOrUpdateQuote;

  /**
   * 获取订单的所有报价
   * GET /api/quotes/order/:orderId
   */
  getOrderQuotes = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const { orderId } = this.validatePathParams(req, ['orderId']);

    // 提取排序参数
    const orderBy = this.extractSortParams(req, this.allowedSortFields);

    const options = { orderBy };

    this.logOperation('get_order_quotes_request', req, {
      orderId,
      userId: user.id,
      options
    });

    const result = await quoteService.getOrderQuotes(orderId, options);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 获取订单的所有报价（别名）
   * GET /api/quotes/orders/:orderId
   */
  getQuotesByOrderId = this.getOrderQuotes;

  /**
   * 获取报价详情
   * GET /api/quotes/:id
   */
  getQuoteById = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const { id: quoteId } = this.validatePathParams(req, ['id']);

    this.logOperation('get_quote_by_id_request', req, {
      quoteId,
      userId: user.id
    });

    const result = await quoteService.getQuoteById(quoteId, user.id, user.role);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 用户选择报价
   * POST /api/quotes/:id/select
   */
  selectQuote = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);
    const { id: quoteId } = this.validatePathParams(req, ['id']);

    this.logOperation('select_quote_request', req, {
      quoteId,
      userId: user.id
    });

    const result = await quoteService.selectQuote(quoteId, user.id, user.role);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 供应商更新报价
   * PATCH /api/quotes/:id
   */
  updateQuote = this.asyncHandler(async (req, res) => {
    const { id: quoteId } = this.validatePathParams(req, ['id']);
    const updateData = this.validateRequestBody(req, []);

    // 从请求头获取供应商信息
    const provider = req.headers['x-provider-name'];
    const accessKey = req.headers['x-access-key'];

    this.logOperation('update_quote_request', req, {
      quoteId,
      provider,
      updateFields: Object.keys(updateData)
    });

    const result = await quoteService.updateQuote(quoteId, updateData, provider, accessKey);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 供应商撤回报价
   * DELETE /api/quotes/:id
   */
  withdrawQuote = this.asyncHandler(async (req, res) => {
    const { id: quoteId } = this.validatePathParams(req, ['id']);

    // 从请求头获取供应商信息
    const provider = req.headers['x-provider-name'];
    const accessKey = req.headers['x-access-key'];

    this.logOperation('withdraw_quote_request', req, {
      quoteId,
      provider
    });

    const result = await quoteService.withdrawQuote(quoteId, provider, accessKey);

    this.sendSuccess(res, result.data, result.message, 200, result.meta);
  });

  /**
   * 获取所有报价（管理员）
   * GET /api/quotes/admin/all
   */
  getAllQuotes = this.asyncHandler(async (req, res) => {
    const user = this.getCurrentUser(req);

    // 提取查询参数
