/**
 * 统一错误处理中间件
 * 提供全局错误处理机制，确保所有错误都以一致的方式处理
 */

const { logger } = require('../config/logger');
const config = require('../config/env');

/**
 * 异步路由错误处理包装器
 * 自动捕获async函数中的未处理异常并传递给错误处理中间件
 * @param {Function} fn - 异步路由处理函数
 * @returns {Function} 包装后的路由处理函数
 */
function asyncHandler(fn) {
  return async (req, res, next) => {
    try {
      await fn(req, res, next);
    } catch (error) {
      next(error);
    }
  };
}

/**
 * 全局错误处理中间件
 * 处理所有未被路由捕获的错误
 * @param {Error} err - 错误对象
 * @param {Object} req - Express请求对象
 * @param {Object} res - Express响应对象
 * @param {Function} next - Express next函数
 */
function globalErrorHandler(err, req, res, next) {
  // 记录详细的错误信息
  logger.error('全局错误处理', {
    message: err.message,
    stack: err.stack,
    url: req.originalUrl,
    method: req.method,
    ip: req.ip,
    userAgent: req.get('User-Agent'),
    userId: req.user?.id,
    timestamp: new Date().toISOString(),
    errorType: err.constructor.name,
    code: err.code
  });

  // 确定错误状态码
  let statusCode = err.statusCode || err.status || 500;

  // 处理特定类型的错误
  if (err.name === 'ValidationError') {
    statusCode = 400;
  } else if (err.name === 'UnauthorizedError' || err.message.includes('unauthorized')) {
    statusCode = 401;
  } else if (err.name === 'ForbiddenError' || err.message.includes('forbidden')) {
    statusCode = 403;
  } else if (err.name === 'NotFoundError' || err.message.includes('not found')) {
    statusCode = 404;
  } else if (err.code === 'SQLITE_CONSTRAINT') {
    statusCode = 409; // Conflict
  }

  // 构建统一的错误响应格式
  const isDevelopment = config.env === 'development';
  const errorResponse = {
    success: false,
    message: isDevelopment ? err.message : getProductionErrorMessage(statusCode),
    code: err.code || 'INTERNAL_ERROR',
    timestamp: new Date().toISOString(),
    path: req.originalUrl,
    method: req.method
  };

  // 在开发环境中包含更多调试信息
  if (isDevelopment) {
    errorResponse.stack = err.stack;
    errorResponse.details = err.details || null;
  }

  // 发送错误响应
  res.status(statusCode).json(errorResponse);
}

/**
 * 获取生产环境友好的错误消息
 * @param {number} statusCode - HTTP状态码
 * @returns {string} 用户友好的错误消息
 */
function getProductionErrorMessage(statusCode) {
  switch (statusCode) {
    case 400:
      return '请求参数错误';
    case 401:
      return '身份验证失败，请重新登录';
    case 403:
      return '权限不足，无法访问此资源';
    case 404:
      return '请求的资源不存在';
    case 409:
      return '数据冲突，请检查输入';
    case 429:
      return '请求过于频繁，请稍后重试';
    case 500:
    default:
      return '服务器内部错误，请稍后重试';
  }
}

/**
 * 404错误处理中间件
 * 处理未匹配到任何路由的请求
 */
function notFoundHandler(req, res, next) {
  const error = new Error(`路由 ${req.originalUrl} 不存在`);
  error.statusCode = 404;
  error.code = 'ROUTE_NOT_FOUND';
  next(error);
}

/**
 * 初始化全局错误处理
 * 设置未捕获异常和Promise拒绝的处理器
 */
function initializeErrorHandling() {
  // 处理未捕获的Promise拒绝
  process.on('unhandledRejection', (reason, promise) => {
    logger.error('未处理的Promise拒绝', {
      reason: reason,
      promise: promise,
      stack: reason?.stack,
      timestamp: new Date().toISOString(),
    });

    // 在生产环境中，记录错误但不退出进程
    // 在开发环境中，可以选择退出进程以便调试
    if (config.env === 'development') {
      console.error('未处理的Promise拒绝，进程将在5秒后退出...');
      setTimeout(() => {
        process.exit(1);
      }, 5000);
    }
  });

  // 处理未捕获的异常
  process.on('uncaughtException', error => {
    logger.error('未捕获的异常', {
      message: error.message,
      stack: error.stack,
      timestamp: new Date().toISOString(),
    });

    // 未捕获的异常通常表示严重问题，应该退出进程
    console.error('未捕获的异常，进程将退出...');
    process.exit(1);
  });

  // 处理进程退出信号
  process.on('SIGTERM', () => {
    logger.info('收到SIGTERM信号，正在优雅关闭...');
    process.exit(0);
  });

  process.on('SIGINT', () => {
    logger.info('收到SIGINT信号，正在优雅关闭...');
    process.exit(0);
  });
}

/**
 * 创建带有重试机制的异步处理器
 * @param {Function} fn - 异步函数
 * @param {number} maxRetries - 最大重试次数
 * @param {number} retryDelay - 重试延迟（毫秒）
 * @returns {Function} 包装后的函数
 */
function asyncHandlerWithRetry(fn, maxRetries = 3, retryDelay = 1000) {
  return asyncHandler(async (req, res, next) => {
    let lastError;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        return await fn(req, res, next);
      } catch (error) {
        lastError = error;

        // 如果是客户端错误（4xx），不重试
        if (error.statusCode && error.statusCode >= 400 && error.statusCode < 500) {
          throw error;
        }

        // 如果不是最后一次尝试，等待后重试
        if (attempt < maxRetries) {
          logger.warn(`操作失败，第${attempt}次重试`, {
            error: error.message,
            url: req.originalUrl,
            attempt: attempt,
            maxRetries: maxRetries,
          });

          await new Promise(resolve => setTimeout(resolve, retryDelay * attempt));
        }
      }
    }

    // 所有重试都失败，抛出最后一个错误
    throw lastError;
  });
}

/**
 * 创建业务错误
 * @param {string} message - 错误消息
 * @param {string} code - 错误代码
 * @param {number} statusCode - HTTP状态码
 * @returns {Error} 业务错误对象
 */
function createBusinessError(message, code = 'BUSINESS_ERROR', statusCode = 400) {
  const error = new Error(message);
  error.code = code;
  error.statusCode = statusCode;
  error.isBusinessError = true;
  return error;
}

module.exports = {
  asyncHandler,
  asyncHandlerWithRetry,
  globalErrorHandler,
  notFoundHandler,
  initializeErrorHandling,
  createBusinessError
};

/**
 * 基础Repository类
 * 提供通用的数据访问方法，遵循Repository模式
 */

const { db, transactionManager } = require('../config/database');
const { logger } = require('../config/logger');

class BaseRepository {
  constructor(tableName, primaryKey = 'id') {
    this.tableName = tableName;
    this.primaryKey = primaryKey;
    this.db = db;
  }

  /**
   * 获取查询构建器
   * @param {Object} trx - 可选的事务对象
   * @returns {Object} Knex查询构建器
   */
  query(trx = null) {
    return (trx || this.db)(this.tableName);
  }

  /**
   * 根据ID查找记录
   * @param {string|number} id - 主键值
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 记录对象或null
   */
  async findById(id, trx = null) {
    try {
      const result = await this.query(trx)
        .where(this.primaryKey, id)
        .first();

      return result || null;
    } catch (error) {
      logger.error('根据ID查找记录失败', {
        table: this.tableName,
        id,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 根据条件查找单条记录
   * @param {Object} conditions - 查询条件
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 记录对象或null
   */
  async findOne(conditions, trx = null) {
    try {
      const result = await this.query(trx)
        .where(conditions)
        .first();

      return result || null;
    } catch (error) {
      logger.error('根据条件查找记录失败', {
        table: this.tableName,
        conditions,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 根据条件查找多条记录
   * @param {Object} conditions - 查询条件
   * @param {Object} options - 查询选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 记录数组
   */
  async findMany(conditions = {}, options = {}, trx = null) {
    try {
      const {
        orderBy = null,
        limit = null,
        offset = null,
        select = '*'
      } = options;

      let query = this.query(trx)
        .select(select)
        .where(conditions);

      if (orderBy) {
        if (Array.isArray(orderBy)) {
          orderBy.forEach(order => {
            if (typeof order === 'string') {
              query = query.orderBy(order);
            } else {
              query = query.orderBy(order.column, order.direction);
            }
          });
        } else if (typeof orderBy === 'string') {
          query = query.orderBy(orderBy);
        } else {
          query = query.orderBy(orderBy.column, orderBy.direction);
        }
      }

      if (limit) {
        query = query.limit(limit);
      }

      if (offset) {
        query = query.offset(offset);
      }

      return await query;
    } catch (error) {
      logger.error('根据条件查找多条记录失败', {
        table: this.tableName,
        conditions,
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取所有记录
   * @param {Object} options - 查询选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 记录数组
   */
  async findAll(options = {}, trx = null) {
    return this.findMany({}, options, trx);
  }

  /**
   * 创建记录
   * @param {Object} data - 要创建的数据
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object>} 创建的记录
   */
  async create(data, trx = null) {
    try {
      const now = new Date().toISOString();
      const dataWithTimestamps = {
        ...data,
        created_at: now,
        updated_at: now
      };

      const [id] = await this.query(trx)
        .insert(dataWithTimestamps)
        .returning(this.primaryKey);

      // 返回创建的记录
      return await this.findById(id || data[this.primaryKey], trx);
    } catch (error) {
      logger.error('创建记录失败', {
        table: this.tableName,
        data,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 批量创建记录
   * @param {Array} dataArray - 要创建的数据数组
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 创建的记录ID数组
   */
  async createMany(dataArray, trx = null) {
    try {
      const now = new Date().toISOString();
      const dataWithTimestamps = dataArray.map(data => ({
        ...data,
        created_at: now,
        updated_at: now
      }));

      const ids = await this.query(trx)
        .insert(dataWithTimestamps)
        .returning(this.primaryKey);

      return ids;
    } catch (error) {
      logger.error('批量创建记录失败', {
        table: this.tableName,
        count: dataArray.length,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 根据ID更新记录
   * @param {string|number} id - 主键值
   * @param {Object} data - 要更新的数据
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 更新后的记录
   */
  async updateById(id, data, trx = null) {
    try {
      const dataWithTimestamp = {
        ...data,
        updated_at: new Date().toISOString()
      };

      const affectedRows = await this.query(trx)
        .where(this.primaryKey, id)
        .update(dataWithTimestamp);

      if (affectedRows === 0) {
        return null;
      }

      return await this.findById(id, trx);
    } catch (error) {
      logger.error('根据ID更新记录失败', {
        table: this.tableName,
        id,
        data,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 根据条件更新记录
   * @param {Object} conditions - 更新条件
   * @param {Object} data - 要更新的数据
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<number>} 受影响的行数
   */
  async updateMany(conditions, data, trx = null) {
    try {
      const dataWithTimestamp = {
        ...data,
        updated_at: new Date().toISOString()
      };

      const affectedRows = await this.query(trx)
        .where(conditions)
        .update(dataWithTimestamp);

      return affectedRows;
    } catch (error) {
      logger.error('根据条件更新记录失败', {
        table: this.tableName,
        conditions,
        data,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 根据ID删除记录
   * @param {string|number} id - 主键值
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<boolean>} 是否删除成功
   */
  async deleteById(id, trx = null) {
    try {
      const affectedRows = await this.query(trx)
        .where(this.primaryKey, id)
        .del();

      return affectedRows > 0;
    } catch (error) {
      logger.error('根据ID删除记录失败', {
        table: this.tableName,
        id,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 根据条件删除记录
   * @param {Object} conditions - 删除条件
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<number>} 删除的记录数
   */
  async deleteMany(conditions, trx = null) {
    try {
      const affectedRows = await this.query(trx)
        .where(conditions)
        .del();

      return affectedRows;
    } catch (error) {
      logger.error('根据条件删除记录失败', {
        table: this.tableName,
        conditions,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 统计记录数
   * @param {Object} conditions - 统计条件
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<number>} 记录数
   */
  async count(conditions = {}, trx = null) {
    try {
      const result = await this.query(trx)
        .where(conditions)
        .count(`${this.primaryKey} as count`)
        .first();

      return parseInt(result.count, 10);
    } catch (error) {
      logger.error('统计记录数失败', {
        table: this.tableName,
        conditions,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 检查记录是否存在
   * @param {Object} conditions - 检查条件
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<boolean>} 是否存在
   */
  async exists(conditions, trx = null) {
    try {
      const count = await this.count(conditions, trx);
      return count > 0;
    } catch (error) {
      logger.error('检查记录存在性失败', {
        table: this.tableName,
        conditions,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 在事务中执行操作
   * @param {Function} callback - 事务回调函数
   * @returns {Promise<any>} 事务结果
   */
  async transaction(callback) {
    return transactionManager.executeTransaction(callback);
  }

  /**
   * 带重试的事务执行
   * @param {Function} callback - 事务回调函数
   * @param {number} maxRetries - 最大重试次数
   * @returns {Promise<any>} 事务结果
   */
  async transactionWithRetry(callback, maxRetries = 3) {
    return transactionManager.executeWithRetry(callback, maxRetries);
  }
}

module.exports = BaseRepository;

/**
 * 订单数据访问层
 * 处理订单相关的数据库操作
 */

const BaseRepository = require('./BaseRepository');
const { logger } = require('../config/logger');

class OrderRepository extends BaseRepository {
  constructor() {
    super('orders', 'id');
  }

  /**
   * 根据用户ID查找订单
   * @param {string} userId - 用户ID
   * @param {Object} options - 查询选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 订单数组
   */
  async findByUserId(userId, options = {}, trx = null) {
    try {
      const {
        status = null,
        limit = null,
        offset = null,
        orderBy = [{ column: 'createdAt', direction: 'desc' }]
      } = options;

      const conditions = { userId };
      if (status) {
        conditions.status = status;
      }

      return await this.findMany(conditions, {
        orderBy,
        limit,
        offset
      }, trx);
    } catch (error) {
      logger.error('根据用户ID查找订单失败', {
        userId,
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 根据状态查找订单
   * @param {string} status - 订单状态
   * @param {Object} options - 查询选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 订单数组
   */
  async findByStatus(status, options = {}, trx = null) {
    try {
      const {
        userId = null,
        limit = null,
        offset = null,
        orderBy = [{ column: 'createdAt', direction: 'desc' }]
      } = options;

      const conditions = { status };
      if (userId) {
        conditions.userId = userId;
      }

      return await this.findMany(conditions, {
        orderBy,
        limit,
        offset
      }, trx);
    } catch (error) {
      logger.error('根据状态查找订单失败', {
        status,
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 根据日期范围查找订单
   * @param {string} startDate - 开始日期
   * @param {string} endDate - 结束日期
   * @param {Object} options - 查询选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 订单数组
   */
  async findByDateRange(startDate, endDate, options = {}, trx = null) {
    try {
      const {
        userId = null,
        status = null,
        limit = null,
        offset = null,
        orderBy = [{ column: 'createdAt', direction: 'desc' }]
      } = options;

      let query = this.query(trx)
        .whereBetween('createdAt', [startDate, endDate]);

      if (userId) {
        query = query.where('userId', userId);
      }

      if (status) {
        query = query.where('status', status);
      }

      if (orderBy) {
        if (Array.isArray(orderBy)) {
          orderBy.forEach(order => {
            query = query.orderBy(order.column, order.direction);
          });
        } else {
          query = query.orderBy(orderBy.column, orderBy.direction);
        }
      }

      if (limit) {
        query = query.limit(limit);
      }

      if (offset) {
        query = query.offset(offset);
      }

      return await query;
    } catch (error) {
      logger.error('根据日期范围查找订单失败', {
        startDate,
        endDate,
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取用户的活跃订单
   * @param {string} userId - 用户ID
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 活跃订单数组
   */
  async getActiveOrdersByUser(userId, trx = null) {
    return this.findByUserId(userId, {
      status: 'active',
      orderBy: [{ column: 'createdAt', direction: 'desc' }]
    }, trx);
  }

  /**
   * 获取待选择供应商的订单
   * @param {Object} options - 查询选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 订单数组
   */
  async getPendingOrders(options = {}, trx = null) {
    try {
      const {
        limit = null,
        offset = null
      } = options;

      return await this.query(trx)
        .where('status', 'active')
        .whereNull('selectedProvider')
        .orderBy('createdAt', 'asc')
        .limit(limit)
        .offset(offset);
    } catch (error) {
      logger.error('获取待选择供应商的订单失败', {
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 更新订单选择的供应商
   * @param {string} orderId - 订单ID
   * @param {string} provider - 供应商名称
   * @param {number} price - 选择的价格
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 更新后的订单
   */
  async selectProvider(orderId, provider, price, trx = null) {
    try {
      const updateData = {
        selectedProvider: provider,
        selectedPrice: price,
        selectedAt: new Date().toISOString(),
        status: 'confirmed'
      };

      return await this.updateById(orderId, updateData, trx);
    } catch (error) {
      logger.error('更新订单选择的供应商失败', {
        orderId,
        provider,
        price,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 取消订单
   * @param {string} orderId - 订单ID
   * @param {string} reason - 取消原因
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 更新后的订单
   */
  async cancelOrder(orderId, reason = null, trx = null) {
    try {
      const updateData = {
        status: 'cancelled',
        cancelledAt: new Date().toISOString()
      };

      if (reason) {
        updateData.cancelReason = reason;
      }

      return await this.updateById(orderId, updateData, trx);
    } catch (error) {
      logger.error('取消订单失败', {
        orderId,
        reason,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 完成订单
   * @param {string} orderId - 订单ID
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 更新后的订单
   */
  async completeOrder(orderId, trx = null) {
    try {
      const updateData = {
        status: 'completed',
        completedAt: new Date().toISOString()
      };

      return await this.updateById(orderId, updateData, trx);
    } catch (error) {
      logger.error('完成订单失败', {
        orderId,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取订单统计信息
   * @param {Object} filters - 过滤条件
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object>} 统计信息
   */
  async getOrderStats(filters = {}, trx = null) {
    try {
      const {
        userId = null,
        startDate = null,
        endDate = null
      } = filters;

      let query = this.query(trx);

      if (userId) {
        query = query.where('userId', userId);
      }

      if (startDate && endDate) {
        query = query.whereBetween('createdAt', [startDate, endDate]);
      }

      const stats = await query
        .select('status')
        .count('* as count')
        .groupBy('status');

      const result = {
        total: 0,
        active: 0,
        confirmed: 0,
        completed: 0,
        cancelled: 0
      };

      stats.forEach(stat => {
        const count = parseInt(stat.count, 10);
        result.total += count;
        result[stat.status] = count;
      });

      return result;
    } catch (error) {
      logger.error('获取订单统计信息失败', {
        filters,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 搜索订单
   * @param {string} searchTerm - 搜索关键词
   * @param {Object} options - 搜索选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 搜索结果
   */
  async searchOrders(searchTerm, options = {}, trx = null) {
    try {
      const {
        userId = null,
        status = null,
        limit = 50,
        offset = 0
      } = options;

      let query = this.query(trx)
        .where(function() {
          this.where('id', 'like', `%${searchTerm}%`)
            .orWhere('warehouse', 'like', `%${searchTerm}%`)
            .orWhere('goods', 'like', `%${searchTerm}%`)
            .orWhere('deliveryAddress', 'like', `%${searchTerm}%`);
        });

      if (userId) {
        query = query.where('userId', userId);
      }

      if (status) {
        query = query.where('status', status);
      }

      return await query
        .orderBy('createdAt', 'desc')
        .limit(limit)
        .offset(offset);
    } catch (error) {
      logger.error('搜索订单失败', {
        searchTerm,
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 检查用户是否有权限访问订单
   * @param {string} orderId - 订单ID
   * @param {string} userId - 用户ID
   * @param {string} userRole - 用户角色
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<boolean>} 是否有权限
   */
  async checkUserAccess(orderId, userId, userRole, trx = null) {
    try {
      // 管理员可以访问所有订单
      if (userRole === 'admin') {
        return true;
      }

      // 普通用户只能访问自己的订单
      const order = await this.findById(orderId, trx);
      return order && order.userId === userId;
    } catch (error) {
      logger.error('检查用户订单访问权限失败', {
        orderId,
        userId,
        userRole,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取用于导出的订单数据
   * @param {Object} filters - 过滤条件
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 订单数组
   */
  async findForExport(filters = {}, trx = null) {
    try {
      const {
        status = null,
        startDate = null,
        endDate = null,
        userId = null
      } = filters;

      let query = this.query(trx)
        .select([
          'id',
          'userId',
          'warehouse',
          'goods',
          'deliveryAddress',
          'status',
          'selectedProvider',
          'selectedPrice',
          'selectedAt',
          'createdAt',
          'updatedAt',
          'completedAt',
          'cancelledAt',
          'cancelReason'
        ]);

      if (status) {
        query = query.where('status', status);
      }

      if (userId) {
        query = query.where('userId', userId);
      }

      if (startDate && endDate) {
        query = query.whereBetween('createdAt', [startDate, endDate]);
      } else if (startDate) {
        query = query.where('createdAt', '>=', startDate);
      } else if (endDate) {
        query = query.where('createdAt', '<=', endDate);
      }

      return await query.orderBy('createdAt', 'desc');
    } catch (error) {
      logger.error('获取导出订单数据失败', {
        filters,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取待处理订单列表（管理员功能）
   * @param {Object} options - 查询选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 待处理订单列表
   */
  async getPendingOrders(options = {}, trx = null) {
    try {
      const {
        limit = 20,
        offset = 0,
        orderBy = [{ column: 'createdAt', direction: 'asc' }]
      } = options;

      let query = this.query(trx)
        .where('status', 'active')
        .whereNull('selectedProvider')
        .limit(limit)
        .offset(offset);

      // 应用排序
      orderBy.forEach(sort => {
        query = query.orderBy(sort.column, sort.direction);
      });

      return await query;
    } catch (error) {
      logger.error('获取待处理订单列表失败', {
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取全局统计信息（管理员）
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object>} 全局统计信息
   */
  async getGlobalStats(trx = null) {
    try {
      const [statusStats, recentStats] = await Promise.all([
        // 按状态统计
        this.query(trx)
          .select('status')
          .count('* as count')
          .groupBy('status'),

        // 最近30天统计
        this.query(trx)
          .where('createdAt', '>=', new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString())
          .count('* as recentCount')
          .first()
      ]);

      const result = {
        total: 0,
        active: 0,
        confirmed: 0,
        completed: 0,
        cancelled: 0,
        recent30Days: parseInt(recentStats?.recentCount || 0, 10)
      };

      statusStats.forEach(stat => {
        const count = parseInt(stat.count, 10);
        result.total += count;
        result[stat.status] = count;
      });

      return result;
    } catch (error) {
      logger.error('获取全局统计信息失败', {
        error: error.message
      });
      throw error;
    }
  }
}

module.exports = OrderRepository;

/**
 * 密码历史记录数据访问层
 * 管理用户密码历史记录的存储和查询
 */

const BaseRepository = require('./BaseRepository');
const { logger } = require('../config/logger');

class PasswordHistoryRepository extends BaseRepository {
  constructor() {
    super('password_history');
  }

  /**
   * 添加密码历史记录
   * @param {number} userId - 用户ID
   * @param {string} passwordHash - 密码哈希值
   * @param {string} ipAddress - IP地址
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object>} 创建的记录
   */
  async addPasswordHistory(userId, passwordHash, ipAddress = null, trx = null) {
    try {
      const historyData = {
        user_id: userId,
        password_hash: passwordHash,
        created_by_ip: ipAddress,
        created_at: new Date()
      };

      const result = await this.create(historyData, trx);

      // 清理旧的密码历史记录，只保留最近的N条
      await this.cleanupOldHistory(userId, 5, trx);

      logger.info('密码历史记录已添加', {
        userId,
        historyId: result.id,
        ipAddress
      });

      return result;
    } catch (error) {
      logger.error('添加密码历史记录失败', {
        userId,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取用户的密码历史记录
   * @param {number} userId - 用户ID
   * @param {number} limit - 限制数量
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 密码历史记录列表
   */
  async getUserPasswordHistory(userId, limit = 5, trx = null) {
    try {
      const query = this.getQueryBuilder(trx)
        .where('user_id', userId)
        .orderBy('created_at', 'desc')
        .limit(limit);

      const history = await query;

      logger.debug('获取用户密码历史记录', {
        userId,
        count: history.length,
        limit
      });

      return history;
    } catch (error) {
      logger.error('获取用户密码历史记录失败', {
        userId,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取用户最近的密码哈希列表
   * @param {number} userId - 用户ID
   * @param {number} count - 数量
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 密码哈希列表
   */
  async getRecentPasswordHashes(userId, count = 5, trx = null) {
    try {
      const query = this.getQueryBuilder(trx)
        .select('password_hash')
        .where('user_id', userId)
        .orderBy('created_at', 'desc')
        .limit(count);

      const results = await query;
      const hashes = results.map(row => row.password_hash);

      logger.debug('获取用户最近密码哈希', {
        userId,
        count: hashes.length
      });

      return hashes;
    } catch (error) {
      logger.error('获取用户最近密码哈希失败', {
        userId,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 清理旧的密码历史记录
   * @param {number} userId - 用户ID
   * @param {number} keepCount - 保留数量
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<number>} 删除的记录数
   */
  async cleanupOldHistory(userId, keepCount = 5, trx = null) {
    try {
      // 获取需要保留的记录ID
      const keepIds = await this.getQueryBuilder(trx)
        .select('id')
        .where('user_id', userId)
        .orderBy('created_at', 'desc')
        .limit(keepCount);

      if (keepIds.length === 0) {
        return 0;
      }

      const keepIdList = keepIds.map(row => row.id);

      // 删除不在保留列表中的记录
      const deletedCount = await this.getQueryBuilder(trx)
        .where('user_id', userId)
        .whereNotIn('id', keepIdList)
        .del();

      if (deletedCount > 0) {
        logger.info('清理旧密码历史记录', {
          userId,
          deletedCount,
          keepCount
        });
      }

      return deletedCount;
    } catch (error) {
      logger.error('清理旧密码历史记录失败', {
        userId,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取密码历史统计信息
   * @param {number} userId - 用户ID
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object>} 统计信息
   */
  async getPasswordHistoryStats(userId, trx = null) {
    try {
      const stats = await this.getQueryBuilder(trx)
        .where('user_id', userId)
        .select([
          this.db.raw('COUNT(*) as total_changes'),
          this.db.raw('MIN(created_at) as first_change'),
          this.db.raw('MAX(created_at) as last_change')
        ])
        .first();

      // 计算平均更改间隔
      if (stats.total_changes > 1 && stats.first_change && stats.last_change) {
        const firstDate = new Date(stats.first_change);
        const lastDate = new Date(stats.last_change);
        const daysDiff = (lastDate - firstDate) / (1000 * 60 * 60 * 24);
        stats.average_change_interval_days = Math.round(daysDiff / (stats.total_changes - 1));
      } else {
        stats.average_change_interval_days = null;
      }

      logger.debug('获取密码历史统计信息', {
        userId,
        totalChanges: stats.total_changes
      });

      return stats;
    } catch (error) {
      logger.error('获取密码历史统计信息失败', {
        userId,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 批量清理所有用户的旧密码历史
   * @param {number} keepCount - 每个用户保留的记录数
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object>} 清理结果
   */
  async batchCleanupAllUsers(keepCount = 5, trx = null) {
    try {
      // 获取所有有密码历史记录的用户
      const users = await this.getQueryBuilder(trx)
        .distinct('user_id')
        .select('user_id');

      let totalDeleted = 0;
      let processedUsers = 0;

      for (const user of users) {
        const deleted = await this.cleanupOldHistory(user.user_id, keepCount, trx);
        totalDeleted += deleted;
        processedUsers++;
      }

      logger.info('批量清理密码历史记录完成', {
        processedUsers,
        totalDeleted,
        keepCount
      });

      return {
        processedUsers,
        totalDeleted,
        keepCount
      };
    } catch (error) {
      logger.error('批量清理密码历史记录失败', {
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 删除用户的所有密码历史记录
   * @param {number} userId - 用户ID
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<number>} 删除的记录数
   */
  async deleteUserHistory(userId, trx = null) {
    try {
      const deletedCount = await this.getQueryBuilder(trx)
        .where('user_id', userId)
        .del();

      logger.info('删除用户密码历史记录', {
        userId,
        deletedCount
      });

      return deletedCount;
    } catch (error) {
      logger.error('删除用户密码历史记录失败', {
        userId,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取密码历史记录的详细信息
   * @param {number} historyId - 历史记录ID
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 历史记录详情
   */
  async getHistoryDetails(historyId, trx = null) {
    try {
      const history = await this.getQueryBuilder(trx)
        .select([
          'id',
          'user_id',
          'created_at',
          'created_by_ip'
        ])
        .where('id', historyId)
        .first();

      if (history) {
        logger.debug('获取密码历史记录详情', {
          historyId,
          userId: history.user_id
        });
      }

      return history;
    } catch (error) {
      logger.error('获取密码历史记录详情失败', {
        historyId,
        error: error.message
      });
      throw error;
    }
  }
}

module.exports = PasswordHistoryRepository;

/**
 * 物流供应商数据访问层
 * 处理物流供应商相关的数据库操作
 */

const BaseRepository = require('./BaseRepository');
const { logger } = require('../config/logger');

class ProviderRepository extends BaseRepository {
  constructor() {
    super('providers', 'id');
  }

  /**
   * 根据访问密钥查找供应商
   * @param {string} accessKey - 访问密钥
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 供应商对象或null
   */
  async findByAccessKey(accessKey, trx = null) {
    try {
      return await this.findOne({ accessKey }, trx);
    } catch (error) {
      logger.error('根据访问密钥查找供应商失败', {
        accessKey,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 根据供应商名称查找
   * @param {string} name - 供应商名称
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 供应商对象或null
   */
  async findByName(name, trx = null) {
    try {
      return await this.findOne({ name }, trx);
    } catch (error) {
      logger.error('根据名称查找供应商失败', {
        name,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 创建供应商
   * @param {Object} providerData - 供应商数据
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object>} 创建的供应商对象
   */
  async createProvider(providerData, trx = null) {
    try {
      const { name, accessKey, contactInfo, isActive = true } = providerData;

      // 检查名称是否已存在
      const existingByName = await this.findByName(name, trx);
      if (existingByName) {
        throw new Error('供应商名称已存在');
      }

      // 检查访问密钥是否已存在
      const existingByKey = await this.findByAccessKey(accessKey, trx);
      if (existingByKey) {
        throw new Error('访问密钥已存在');
      }

      const newProvider = {
        id: this.generateProviderId(),
        name,
        accessKey,
        contactInfo: JSON.stringify(contactInfo || {}),
        isActive: isActive ? 1 : 0
      };

      return await this.create(newProvider, trx);
    } catch (error) {
      logger.error('创建供应商失败', {
        providerData,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 更新供应商信息
   * @param {string} providerId - 供应商ID
   * @param {Object} updateData - 更新数据
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 更新后的供应商对象
   */
  async updateProvider(providerId, updateData, trx = null) {
    try {
      // 过滤掉不允许直接更新的字段
      const { id: _id, created_at: _created_at, ...allowedData } = updateData;

      // 如果更新名称，需要检查是否重复
      if (allowedData.name) {
        const existingProvider = await this.findByName(allowedData.name, trx);
        if (existingProvider && existingProvider.id !== providerId) {
          throw new Error('供应商名称已被其他供应商使用');
        }
      }

      // 如果更新访问密钥，需要检查是否重复
      if (allowedData.accessKey) {
        const existingProvider = await this.findByAccessKey(allowedData.accessKey, trx);
        if (existingProvider && existingProvider.id !== providerId) {
          throw new Error('访问密钥已被其他供应商使用');
        }
      }

      // 如果更新联系信息，需要序列化
      if (allowedData.contactInfo && typeof allowedData.contactInfo === 'object') {
        allowedData.contactInfo = JSON.stringify(allowedData.contactInfo);
      }

      return await this.updateById(providerId, allowedData, trx);
    } catch (error) {
      logger.error('更新供应商信息失败', {
        providerId,
        updateData,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 激活/禁用供应商
   * @param {string} providerId - 供应商ID
   * @param {boolean} isActive - 是否激活
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 更新后的供应商对象
   */
  async setProviderActive(providerId, isActive, trx = null) {
    try {
      return await this.updateById(providerId, {
        isActive: isActive ? 1 : 0
      }, trx);
    } catch (error) {
      logger.error('设置供应商状态失败', {
        providerId,
        isActive,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取活跃供应商列表
   * @param {Object} options - 查询选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 活跃供应商数组
   */
  async getActiveProviders(options = {}, trx = null) {
    try {
      const {
        limit = null,
        offset = null,
        orderBy = [{ column: 'name', direction: 'asc' }]
      } = options;

      const providers = await this.findMany({ isActive: 1 }, {
        orderBy,
        limit,
        offset
      }, trx);

      // 解析联系信息
      return providers.map(provider => ({
        ...provider,
        contactInfo: this.parseContactInfo(provider.contactInfo)
      }));
    } catch (error) {
      logger.error('获取活跃供应商列表失败', {
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 验证供应商访问权限
   * @param {string} accessKey - 访问密钥
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 验证成功返回供应商对象，失败返回null
   */
  async validateAccess(accessKey, trx = null) {
    try {
      const provider = await this.findByAccessKey(accessKey, trx);

      if (!provider) {
        return null;
      }

      // 检查供应商是否激活
      if (!provider.isActive) {
        throw new Error('供应商账户已被禁用');
      }

      return {
        ...provider,
        contactInfo: this.parseContactInfo(provider.contactInfo)
      };
    } catch (error) {
      logger.error('验证供应商访问权限失败', {
        accessKey,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 生成供应商ID
   * @returns {string} 供应商ID
   */
  generateProviderId() {
    return `provider_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  /**
   * 解析联系信息JSON
   * @param {string} contactInfoStr - 联系信息JSON字符串
   * @returns {Object} 解析后的联系信息对象
   */
  parseContactInfo(contactInfoStr) {
    try {
      return contactInfoStr ? JSON.parse(contactInfoStr) : {};
    } catch (error) {
      logger.warn('解析供应商联系信息失败', {
        contactInfoStr,
        error: error.message
      });
      return {};
    }
  }

  /**
   * 检查供应商名称是否可用
   * @param {string} name - 供应商名称
   * @param {string} excludeProviderId - 排除的供应商ID（用于更新时检查）
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<boolean>} 是否可用
   */
  async isNameAvailable(name, excludeProviderId = null, trx = null) {
    try {
      const existingProvider = await this.findByName(name, trx);

      if (!existingProvider) {
        return true;
      }

      // 如果是更新操作，排除当前供应商
      if (excludeProviderId && existingProvider.id === excludeProviderId) {
        return true;
      }

      return false;
    } catch (error) {
      logger.error('检查供应商名称可用性失败', {
        name,
        excludeProviderId,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取活跃供应商列表
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 活跃供应商列表
   */
  async findActiveProviders(trx = null) {
    try {
      return await this.findMany({ isActive: 1 }, {}, trx);
    } catch (error) {
      logger.error('获取活跃供应商列表失败', {
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 检查访问密钥是否可用
   * @param {string} accessKey - 访问密钥
   * @param {string} excludeProviderId - 排除的供应商ID（用于更新时检查）
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<boolean>} 是否可用
   */
  async isAccessKeyAvailable(accessKey, excludeProviderId = null, trx = null) {
    try {
      const existingProvider = await this.findByAccessKey(accessKey, trx);

      if (!existingProvider) {
        return true;
      }

      // 如果是更新操作，排除当前供应商
      if (excludeProviderId && existingProvider.id === excludeProviderId) {
        return true;
      }

      return false;
    } catch (error) {
      logger.error('检查访问密钥可用性失败', {
        accessKey,
        excludeProviderId,
        error: error.message
      });
      throw error;
    }
  }
}

