  }

  /**
   * 删除订单的所有报价
   * @param {string} orderId - 订单ID
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<number>} 删除的报价数量
   */
  async deleteByOrderId(orderId, trx = null) {
    try {
      return await this.deleteMany({ orderId }, trx);
    } catch (error) {
      logger.error('删除订单报价失败', {
