   * @param {Object} userData - 用户数据
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object>} 创建的用户对象
   */
  async createUser(userData, trx = null) {
    try {
      const { email, password, name, role = 'user' } = userData;

      // 检查邮箱是否已存在
      const existingUser = await this.findByEmail(email, trx);
      if (existingUser) {
        throw new Error('邮箱已被注册');
      }

      // 加密密码
      const hashedPassword = await bcrypt.hash(password, 12);

      const newUser = {
        id: this.generateUserId(),
        email: email.toLowerCase(),
        password: hashedPassword,
        name,
        role,
        isActive: 1
      };

      const createdUser = await this.create(newUser, trx);

      // 返回用户信息时不包含密码
      const { password: _, ...userWithoutPassword } = createdUser;
      return userWithoutPassword;
    } catch (error) {
      logger.error('创建用户失败', {
        email: userData.email,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 验证用户密码
   * @param {string} email - 用户邮箱
   * @param {string} password - 密码
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 验证成功返回用户对象，失败返回null
   */
  async validateUser(email, password, trx = null) {
    try {
      const user = await this.findByEmail(email, trx);
      if (!user) {
        return null;
      }

      // 检查用户是否激活
      if (!user.isActive) {
        throw new Error('用户账户已被禁用');
      }

      // 验证密码
      const isValidPassword = await bcrypt.compare(password, user.password);
      if (!isValidPassword) {
        return null;
      }

      // 返回用户信息时不包含密码
      const { password: _, ...userWithoutPassword } = user;
      return userWithoutPassword;
    } catch (error) {
      logger.error('验证用户失败', {
        email,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 更新用户密码
   * @param {string} userId - 用户ID
   * @param {string} newPassword - 新密码
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<boolean>} 是否更新成功
   */
  async updatePassword(userId, newPassword, trx = null) {
    try {
      const hashedPassword = await bcrypt.hash(newPassword, 12);

      const updatedUser = await this.updateById(userId, {
        password: hashedPassword
      }, trx);

      return !!updatedUser;
    } catch (error) {
      logger.error('更新用户密码失败', {
        userId,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 更新用户信息
   * @param {string} userId - 用户ID
   * @param {Object} updateData - 更新数据
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 更新后的用户对象
   */
  async updateUser(userId, updateData, trx = null) {
    try {
      // 过滤掉不允许直接更新的字段
      const { password: _password, id: _id, created_at: _created_at, ...allowedData } = updateData;

      // 如果更新邮箱，需要检查是否重复
      if (allowedData.email) {
        allowedData.email = allowedData.email.toLowerCase();
        const existingUser = await this.findByEmail(allowedData.email, trx);
        if (existingUser && existingUser.id !== userId) {
          throw new Error('邮箱已被其他用户使用');
        }
      }

      const updatedUser = await this.updateById(userId, allowedData, trx);

      if (updatedUser) {
        // 返回用户信息时不包含密码
        const { password: _, ...userWithoutPassword } = updatedUser;
        return userWithoutPassword;
      }

      return null;
    } catch (error) {
      logger.error('更新用户信息失败', {
        userId,
        updateData,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 激活/禁用用户
   * @param {string} userId - 用户ID
   * @param {boolean} isActive - 是否激活
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object|null>} 更新后的用户对象
   */
  async setUserActive(userId, isActive, trx = null) {
    try {
      const updatedUser = await this.updateById(userId, {
        isActive: isActive ? 1 : 0
      }, trx);

      if (updatedUser) {
        const { password: _, ...userWithoutPassword } = updatedUser;
        return userWithoutPassword;
      }

      return null;
    } catch (error) {
      logger.error('设置用户状态失败', {
        userId,
        isActive,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 根据角色查找用户
   * @param {string} role - 用户角色
   * @param {Object} options - 查询选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 用户数组
   */
  async findByRole(role, options = {}, trx = null) {
    try {
      const {
        isActive = null,
        limit = null,
        offset = null,
        orderBy = [{ column: 'created_at', direction: 'desc' }]
      } = options;

      const conditions = { role };
      if (isActive !== null) {
        conditions.isActive = isActive ? 1 : 0;
      }

      const users = await this.findMany(conditions, {
        orderBy,
        limit,
        offset,
        select: ['id', 'email', 'name', 'role', 'isActive', 'created_at', 'updated_at']
      }, trx);

      return users;
    } catch (error) {
      logger.error('根据角色查找用户失败', {
        role,
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取活跃用户列表
   * @param {Object} options - 查询选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 活跃用户数组
   */
  async getActiveUsers(options = {}, trx = null) {
    try {
      const {
        role = null,
        limit = null,
        offset = null,
        orderBy = [{ column: 'created_at', direction: 'desc' }]
      } = options;

      const conditions = { isActive: 1 };
      if (role) {
        conditions.role = role;
      }

      return await this.findMany(conditions, {
        orderBy,
        limit,
        offset,
        select: ['id', 'email', 'name', 'role', 'isActive', 'created_at', 'updated_at']
      }, trx);
    } catch (error) {
      logger.error('获取活跃用户列表失败', {
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 搜索用户
   * @param {string} searchTerm - 搜索关键词
   * @param {Object} options - 搜索选项
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 搜索结果
   */
  async searchUsers(searchTerm, options = {}, trx = null) {
    try {
      const {
        role = null,
        isActive = null,
        limit = 50,
        offset = 0
      } = options;

      let query = this.query(trx)
        .select(['id', 'email', 'name', 'role', 'isActive', 'created_at', 'updated_at'])
        .where(function() {
          this.where('email', 'like', `%${searchTerm}%`)
            .orWhere('name', 'like', `%${searchTerm}%`);
        });

      if (role) {
        query = query.where('role', role);
      }

      if (isActive !== null) {
        query = query.where('isActive', isActive ? 1 : 0);
      }

      return await query
        .orderBy('created_at', 'desc')
        .limit(limit)
        .offset(offset);
    } catch (error) {
      logger.error('搜索用户失败', {
        searchTerm,
        options,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取用户统计信息
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Object>} 统计信息
   */
  async getUserStats(trx = null) {
    try {
      const stats = await this.query(trx)
        .select('role', 'isActive')
        .count('* as count')
        .groupBy('role', 'isActive');

      const result = {
        total: 0,
        active: 0,
        inactive: 0,
        byRole: {}
      };

      stats.forEach(stat => {
        const count = parseInt(stat.count, 10);
        result.total += count;

        if (stat.isActive) {
          result.active += count;
        } else {
          result.inactive += count;
        }

        if (!result.byRole[stat.role]) {
          result.byRole[stat.role] = { active: 0, inactive: 0, total: 0 };
        }

        if (stat.isActive) {
          result.byRole[stat.role].active += count;
        } else {
          result.byRole[stat.role].inactive += count;
        }
        result.byRole[stat.role].total += count;
      });

      return result;
    } catch (error) {
      logger.error('获取用户统计信息失败', {
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 生成用户ID
   * @returns {string} 用户ID
   */
  generateUserId() {
    return `user_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  /**
   * 检查邮箱是否可用
   * @param {string} email - 邮箱
   * @param {string} excludeUserId - 排除的用户ID（用于更新时检查）
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<boolean>} 是否可用
   */
  async isEmailAvailable(email, excludeUserId = null, trx = null) {
    try {
      const existingUser = await this.findByEmail(email, trx);

      if (!existingUser) {
        return true;
      }

      // 如果是更新操作，排除当前用户
      if (excludeUserId && existingUser.id === excludeUserId) {
        return true;
      }

      return false;
    } catch (error) {
      logger.error('检查邮箱可用性失败', {
        email,
        excludeUserId,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取用于导出的用户数据
   * @param {Object} filters - 过滤条件
   * @param {Object} trx - 可选的事务对象
   * @returns {Promise<Array>} 用户数组
   */
  async findForExport(filters = {}, trx = null) {
    try {
      const {
        role = null,
        isActive = null,
        startDate = null,
        endDate = null
      } = filters;

      let query = this.query(trx)
        .select([
          'id',
          'email',
          'name',
          'role',
          'isActive',
          'created_at',
          'updated_at',
          'last_login_at'
        ]);

      if (role) {
        query = query.where('role', role);
      }

      if (isActive !== null) {
        query = query.where('isActive', isActive);
      }

      if (startDate && endDate) {
        query = query.whereBetween('created_at', [startDate, endDate]);
      } else if (startDate) {
        query = query.where('created_at', '>=', startDate);
      } else if (endDate) {
        query = query.where('created_at', '<=', endDate);
      }

      return await query.orderBy('created_at', 'desc');
    } catch (error) {
      logger.error('获取导出用户数据失败', {
        filters,
        error: error.message
      });
      throw error;
    }
  }
}

module.exports = UserRepository;

/**
 * Repository工厂和统一导出
 * 提供统一的数据访问层接口
 */

const OrderRepository = require('./OrderRepository');
const QuoteRepository = require('./QuoteRepository');
const UserRepository = require('./UserRepository');
const ProviderRepository = require('./ProviderRepository');
const { logger } = require('../config/logger');

class RepositoryFactory {
  constructor() {
    this.repositories = new Map();
    this.initialized = false;
  }

  /**
   * 初始化所有Repository
   */
  initialize() {
    if (this.initialized) {
      return;
    }

    try {
      // 创建Repository实例
      this.repositories.set('order', new OrderRepository());
      this.repositories.set('quote', new QuoteRepository());
      this.repositories.set('user', new UserRepository());
      this.repositories.set('provider', new ProviderRepository());

      this.initialized = true;
      logger.info('Repository工厂初始化完成', {
        repositories: Array.from(this.repositories.keys())
      });
    } catch (error) {
      logger.error('Repository工厂初始化失败', {
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取Repository实例
   * @param {string} name - Repository名称
   * @returns {Object} Repository实例
   */
  getRepository(name) {
    if (!this.initialized) {
      this.initialize();
    }

    const repository = this.repositories.get(name);
    if (!repository) {
      throw new Error(`Repository '${name}' 不存在`);
    }

    return repository;
  }

  /**
   * 获取订单Repository
   * @returns {OrderRepository} 订单Repository实例
   */
  get order() {
    return this.getRepository('order');
  }

  /**
   * 获取报价Repository
   * @returns {QuoteRepository} 报价Repository实例
   */
  get quote() {
    return this.getRepository('quote');
  }

  /**
   * 获取用户Repository
   * @returns {UserRepository} 用户Repository实例
   */
  get user() {
    return this.getRepository('user');
  }

  /**
   * 获取供应商Repository
   * @returns {ProviderRepository} 供应商Repository实例
   */
  get provider() {
    return this.getRepository('provider');
  }

  /**
   * 获取所有Repository的健康状态
   * @returns {Promise<Object>} 健康状态信息
   */
  async getHealthStatus() {
    if (!this.initialized) {
      return { status: 'not_initialized' };
    }

    const status = {
      status: 'healthy',
      repositories: {},
      timestamp: new Date().toISOString()
    };

    for (const [name, repository] of this.repositories) {
      try {
        // 尝试执行一个简单的查询来检查Repository健康状态
        await repository.count();
        status.repositories[name] = 'healthy';
      } catch (error) {
        status.repositories[name] = 'unhealthy';
        status.status = 'degraded';
        logger.warn(`Repository '${name}' 健康检查失败`, {
          error: error.message
        });
      }
    }

    return status;
  }

  /**
   * 重置所有Repository（主要用于测试）
   */
  reset() {
    this.repositories.clear();
    this.initialized = false;
    logger.info('Repository工厂已重置');
  }
}

// 创建全局Repository工厂实例
const repositoryFactory = new RepositoryFactory();

// 便捷的导出方式
module.exports = {
  RepositoryFactory,
  repositoryFactory,

  // 直接导出Repository类
  OrderRepository,
  QuoteRepository,
  UserRepository,
  ProviderRepository,

  // 便捷的访问方式
  get orderRepo() {
    return repositoryFactory.order;
  },

  get quoteRepo() {
    return repositoryFactory.quote;
  },

  get userRepo() {
    return repositoryFactory.user;
  },

  get providerRepo() {
    return repositoryFactory.provider;
  }
};

/**
 * 基础Service类
 * 提供通用的业务逻辑方法和错误处理
 */

const { logger } = require('../config/logger');

class BaseService {
  constructor(name) {
    this.serviceName = name;
  }

  /**
   * 记录业务操作日志
   * @param {string} action - 操作名称
   * @param {Object} data - 操作数据
   * @param {string} level - 日志级别
   */
  logOperation(action, data = {}, level = 'info') {
    const logData = {
      service: this.serviceName,
      action,
      ...data,
      timestamp: new Date().toISOString()
    };

    logger[level](`${this.serviceName} - ${action}`, logData);
  }

  /**
   * 记录错误日志
   * @param {string} action - 操作名称
   * @param {Error} error - 错误对象
   * @param {Object} context - 上下文信息
   */
  logError(action, error, context = {}) {
    this.logOperation(action, {
      error: error.message,
      stack: error.stack,
      ...context
    }, 'error');
  }

  /**
   * 验证必需参数
   * @param {Object} params - 参数对象
   * @param {Array} requiredFields - 必需字段数组
   * @throws {Error} 参数验证失败时抛出错误
   */
  validateRequiredParams(params, requiredFields) {
    const missingFields = [];

    for (const field of requiredFields) {
      if (params[field] === undefined || params[field] === null || params[field] === '') {
        missingFields.push(field);
      }
    }

    if (missingFields.length > 0) {
      throw new Error(`缺少必需参数: ${missingFields.join(', ')}`);
    }
  }

  /**
   * 验证参数类型
   * @param {Object} params - 参数对象
   * @param {Object} typeMap - 类型映射 {field: 'string'|'number'|'boolean'|'object'|'array'}
   * @throws {Error} 类型验证失败时抛出错误
   */
  validateParamTypes(params, typeMap) {
    const typeErrors = [];

    for (const [field, expectedType] of Object.entries(typeMap)) {
      if (params[field] !== undefined) {
        const actualType = Array.isArray(params[field]) ? 'array' : typeof params[field];

        if (actualType !== expectedType) {
          typeErrors.push(`${field} 应该是 ${expectedType} 类型，实际是 ${actualType}`);
        }
      }
    }

    if (typeErrors.length > 0) {
      throw new Error(`参数类型错误: ${typeErrors.join('; ')}`);
    }
  }

  /**
   * 创建业务错误 - 使用统一的错误创建方法
   * @param {string} message - 错误消息
   * @param {string} code - 错误代码
   * @param {number} statusCode - HTTP状态码
   * @returns {Error} 业务错误对象
   */
  createBusinessError(message, code = 'BUSINESS_ERROR', statusCode = 400) {
    const { createBusinessError } = require('../middleware/errorHandler');
    const error = createBusinessError(message, code, statusCode);
    error.service = this.serviceName; // 添加服务上下文
    return error;
  }

  /**
   * 处理异步操作
   * @param {Function} operation - 异步操作函数
   * @param {string} operationName - 操作名称
   * @param {Object} context - 上下文信息
   * @returns {Promise<any>} 操作结果
   */
  async handleAsyncOperation(operation, operationName, context = {}) {
    try {
      this.logOperation(`${operationName}_start`, context, 'debug');

      const startTime = Date.now();
      const result = await operation();
      const duration = Date.now() - startTime;

      this.logOperation(`${operationName}_success`, {
        ...context,
        duration: `${duration}ms`
      }, 'debug');

      return result;
    } catch (error) {
      this.logError(`${operationName}_failed`, error, context);
      throw error;
    }
  }

  /**
   * 分页参数验证和标准化
   * @param {Object} params - 分页参数
   * @returns {Object} 标准化的分页参数
   */
  normalizePaginationParams(params = {}) {
    const {
      page = 1,
      limit = 20,
      offset = null
    } = params;

    // 验证参数
    const pageNum = parseInt(page, 10);
    const limitNum = parseInt(limit, 10);

    if (isNaN(pageNum) || pageNum < 1) {
      throw this.createBusinessError('页码必须是大于0的整数');
    }

    if (isNaN(limitNum) || limitNum < 1 || limitNum > 100) {
      throw this.createBusinessError('每页数量必须是1-100之间的整数');
    }

    return {
      page: pageNum,
      limit: limitNum,
      offset: offset !== null ? parseInt(offset, 10) : (pageNum - 1) * limitNum
    };
  }

  /**
   * 排序参数验证和标准化
   * @param {string|Object|Array} orderBy - 排序参数
   * @param {Array} allowedFields - 允许排序的字段
   * @returns {Array} 标准化的排序参数
   */
  normalizeOrderByParams(orderBy, allowedFields = []) {
    if (!orderBy) {
      return [];
    }

    let orderByArray = [];

    if (typeof orderBy === 'string') {
      // 支持 "field" 或 "field:desc" 格式
      const [field, direction = 'asc'] = orderBy.split(':');
      orderByArray = [{ column: field, direction }];
    } else if (Array.isArray(orderBy)) {
      orderByArray = orderBy;
    } else if (typeof orderBy === 'object') {
      orderByArray = [orderBy];
    }

    // 验证字段和方向
    const validDirections = ['asc', 'desc'];
    const validatedOrderBy = [];

    for (const order of orderByArray) {
      if (typeof order === 'string') {
        const [field, direction = 'asc'] = order.split(':');
        validatedOrderBy.push({ column: field, direction });
      } else if (order.column) {
        validatedOrderBy.push({
          column: order.column,
          direction: order.direction || 'asc'
        });
      }
    }

    // 检查字段是否允许
    if (allowedFields.length > 0) {
      for (const order of validatedOrderBy) {
        if (!allowedFields.includes(order.column)) {
          throw this.createBusinessError(`不允许按字段 '${order.column}' 排序`);
        }

        if (!validDirections.includes(order.direction.toLowerCase())) {
          throw this.createBusinessError(`排序方向必须是 'asc' 或 'desc'`);
        }

        order.direction = order.direction.toLowerCase();
      }
    }

    return validatedOrderBy;
  }

  /**
   * 构建标准响应格式
   * @param {any} data - 响应数据
   * @param {string} message - 响应消息
   * @param {Object} meta - 元数据（如分页信息）
   * @returns {Object} 标准响应对象
   */
  buildResponse(data, message = 'success', meta = {}) {
    return {
      success: true,
      message,
      data,
      meta: {
        timestamp: new Date().toISOString(),
        ...meta
      }
    };
  }

  /**
   * 构建分页响应
   * @param {Array} items - 数据项
   * @param {number} total - 总数
   * @param {Object} pagination - 分页参数
   * @returns {Object} 分页响应对象
   */
  buildPaginatedResponse(items, total, pagination) {
    const { page, limit } = pagination;
    const totalPages = Math.ceil(total / limit);

    return this.buildResponse(items, 'success', {
      pagination: {
        page,
        limit,
        total,
        totalPages,
        hasNext: page < totalPages,
        hasPrev: page > 1
      }
    });
  }

  /**
   * 构建错误响应
   * @param {Error} error - 错误对象
   * @returns {Object} 错误响应对象
   */
  buildErrorResponse(error) {
    return {
      success: false,
      message: error.message,
      code: error.code || 'UNKNOWN_ERROR',
      timestamp: new Date().toISOString()
    };
  }

  /**
   * 清理敏感数据
   * @param {Object} data - 数据对象
   * @param {Array} sensitiveFields - 敏感字段数组
   * @returns {Object} 清理后的数据对象
   */
  sanitizeData(data, sensitiveFields = ['password', 'accessKey', 'secret']) {
    if (!data || typeof data !== 'object') {
      return data;
    }

    if (Array.isArray(data)) {
      return data.map(item => this.sanitizeData(item, sensitiveFields));
    }

    const sanitized = { ...data };

    for (const field of sensitiveFields) {
      if (sanitized[field] !== undefined) {
        delete sanitized[field];
      }
    }

    return sanitized;
  }

  /**
   * 延迟执行
   * @param {number} ms - 延迟毫秒数
   * @returns {Promise<void>}
   */
  delay(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  /**
   * 重试机制
   * @param {Function} operation - 要重试的操作
   * @param {number} maxRetries - 最大重试次数
   * @param {number} baseDelay - 基础延迟时间（毫秒）
   * @returns {Promise<any>} 操作结果
   */
  async retry(operation, maxRetries = 3, baseDelay = 1000) {
    let lastError;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        return await operation();
      } catch (error) {
        lastError = error;

        if (attempt === maxRetries) {
          break;
        }

        // 指数退避
        const delay = baseDelay * Math.pow(2, attempt - 1);
        this.logOperation('retry_attempt', {
          attempt,
          maxRetries,
          delay,
          error: error.message
        }, 'warn');

        await this.delay(delay);
      }
    }

    throw lastError;
  }

  /**
   * 并发执行多个操作
   * @param {Object} operations - 操作对象 {key: asyncFunction}
   * @param {string} operationName - 操作名称
   * @returns {Promise<Object>} 并发执行结果
   */
  async executeParallel(operations, operationName = 'parallel_operations') {
    const AsyncOptimizer = require('../utils/AsyncOptimizer');

    return this.handleAsyncOperation(async () => {
      const result = await AsyncOptimizer.executeParallel(operations);

      this.logOperation(`${operationName}_parallel_complete`, {
        operationCount: Object.keys(operations).length,
        successCount: Object.keys(result.data).length,
        errorCount: result.errors.length
      });

      return result;
    }, operationName);
  }

  /**
   * 批量执行任务
   * @param {Array} tasks - 任务数组
   * @param {Object} options - 执行选项
   * @param {string} operationName - 操作名称
   * @returns {Promise<Object>} 批量执行结果
   */
  async executeBatch(tasks, options = {}, operationName = 'batch_operations') {
    const AsyncOptimizer = require('../utils/AsyncOptimizer');

    return this.handleAsyncOperation(async () => {
      const result = await AsyncOptimizer.executeBatch(tasks, options);

      this.logOperation(`${operationName}_batch_complete`, {
        totalTasks: tasks.length,
        successCount: result.stats.successful,
        errorCount: result.stats.failed,
        duration: result.stats.duration
      });

      return result;
    }, operationName);
  }
}

module.exports = BaseService;

/**
 * 通知业务逻辑服务
 * 处理各种通知相关的业务逻辑
 */

const BaseService = require('./BaseService');
const config = require('../config/env');

class NotificationService extends BaseService {
  constructor() {
    super('NotificationService');
    this.webhookUrl = config.wechat?.webhookUrl;
    this.retryAttempts = 3;
    this.retryDelay = 1000; // 1秒
  }

  /**
   * 发送新订单通知给所有供应商
   * @param {Object} order - 订单信息
   * @param {Array} providers - 供应商列表
   * @returns {Promise<Object>} 通知发送结果
   */
  async notifyProvidersNewOrder(order, providers = []) {
    return this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ order }, ['order']);
      this.validateRequiredParams(order, ['id', 'warehouse', 'goods', 'deliveryAddress']);

      if (!Array.isArray(providers) || providers.length === 0) {
        this.logOperation('no_providers_to_notify', { orderId: order.id }, 'warn');
        return this.buildResponse(null, '没有可通知的供应商');
      }

      // 使用并发处理优化性能
      const AsyncOptimizer = require('../utils/AsyncOptimizer');

      // 为每个供应商创建通知任务
      const notificationTasks = providers.map(provider => async () => {
        const message = this.generateNewOrderMessage(order, provider);
        const result = await this.sendNotification(message, 'new_order', {
          orderId: order.id,
          provider: provider.name
        });

        return {
          provider: provider.name,
          status: 'sent',
          messageId: result.messageId
        };
      });

      // 并发执行通知任务
      const batchResult = await AsyncOptimizer.executeBatch(notificationTasks, {
        maxConcurrency: 3, // 限制并发数避免过载
        retryAttempts: 2,
        retryDelay: 1000,
        failFast: false // 不因单个失败而停止
      });

      const notifications = batchResult.results;
      const errors = batchResult.errors.map(error => ({
        provider: providers[error.index].name,
        status: 'failed',
        error: error.error
      }));

      this.logOperation('providers_notified', {
        orderId: order.id,
        totalProviders: providers.length,
        successCount: notifications.length,
        errorCount: errors.length
      });

      return this.buildResponse({
        notifications,
        errors,
        summary: {
          total: providers.length,
          success: notifications.length,
          failed: errors.length
        }
      }, '供应商通知发送完成');
    }, 'notifyProvidersNewOrder', { orderId: order.id });
  }

  /**
   * 发送报价通知给用户
   * @param {Object} quote - 报价信息
   * @param {Object} order - 订单信息
   * @param {Object} user - 用户信息
   * @returns {Promise<Object>} 通知发送结果
   */
  async notifyUserNewQuote(quote, order, user) {
    return this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ quote, order, user }, ['quote', 'order', 'user']);
      this.validateRequiredParams(quote, ['provider', 'price', 'estimatedDelivery']);
      this.validateRequiredParams(order, ['id', 'warehouse', 'goods']);
      this.validateRequiredParams(user, ['id', 'name']);

      const message = this.generateQuoteNotificationMessage(quote, order, user);

      const result = await this.sendNotification(message, 'new_quote', {
        orderId: order.id,
        userId: user.id,
        provider: quote.provider,
        price: quote.price
      });

      this.logOperation('user_quote_notification_sent', {
        orderId: order.id,
        userId: user.id,
        provider: quote.provider,
        messageId: result.messageId
      });

      return this.buildResponse(result, '报价通知发送成功');
    }, 'notifyUserNewQuote', { orderId: order.id, userId: user.id });
  }

  /**
   * 发送订单状态变更通知
   * @param {Object} order - 订单信息
   * @param {Object} user - 用户信息
   * @param {string} previousStatus - 之前的状态
   * @returns {Promise<Object>} 通知发送结果
   */
  async notifyOrderStatusChange(order, user, previousStatus) {
    return this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ order, user, previousStatus }, ['order', 'user', 'previousStatus']);
      this.validateRequiredParams(order, ['id', 'status']);
      this.validateRequiredParams(user, ['id', 'name']);

      const message = this.generateOrderStatusMessage(order, user, previousStatus);

      const result = await this.sendNotification(message, 'order_status_change', {
        orderId: order.id,
        userId: user.id,
        newStatus: order.status,
        previousStatus
      });

      this.logOperation('order_status_notification_sent', {
        orderId: order.id,
        userId: user.id,
        newStatus: order.status,
        previousStatus,
        messageId: result.messageId
      });

      return this.buildResponse(result, '订单状态通知发送成功');
    }, 'notifyOrderStatusChange', { orderId: order.id, userId: user.id });
  }

  /**
   * 发送系统通知
   * @param {string} title - 通知标题
   * @param {string} content - 通知内容
   * @param {string} type - 通知类型
   * @param {Object} metadata - 元数据
   * @returns {Promise<Object>} 通知发送结果
   */
  async sendSystemNotification(title, content, type = 'system', metadata = {}) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ title, content }, ['title', 'content']);

      const message = {
        msgtype: 'text',
        text: {
          content: `【系统通知】\n标题：${title}\n内容：${content}\n时间：${new Date().toLocaleString('zh-CN')}`
        }
      };

      const result = await this.sendNotification(message, type, metadata);

      this.logOperation('system_notification_sent', {
        title,
        type,
        messageId: result.messageId,
        ...metadata
      });

      return this.buildResponse(result, '系统通知发送成功');
    }, 'sendSystemNotification', { title, type });
  }

  /**
   * 生成新订单通知消息
   * @param {Object} order - 订单信息
   * @param {Object} provider - 供应商信息
   * @returns {Object} 通知消息
   */
  generateNewOrderMessage(order, provider) {
    const content = `【新订单通知】
供应商：${provider.name}
订单编号：${order.id}
发货仓库：${order.warehouse}
货物信息：${order.goods}
配送地址：${order.deliveryAddress}
创建时间：${new Date(order.createdAt).toLocaleString('zh-CN')}

请及时登录系统查看详情并提供报价。`;

    return {
      msgtype: 'text',
      text: {
        content,
        mentioned_list: provider.mentionUsers || []
      }
    };
  }

  /**
   * 生成报价通知消息
   * @param {Object} quote - 报价信息
   * @param {Object} order - 订单信息
   * @param {Object} user - 用户信息
   * @returns {Object} 通知消息
   */
  generateQuoteNotificationMessage(quote, order, user) {
    const content = `【新报价通知】
用户：${user.name}
订单编号：${order.id}
货物信息：${order.goods}
供应商：${quote.provider}
报价金额：¥${quote.price}
预计送达：${new Date(quote.estimatedDelivery).toLocaleString('zh-CN')}

请登录系统查看详细报价信息。`;

    return {
      msgtype: 'text',
      text: {
        content
      }
    };
  }

  /**
   * 生成订单状态变更消息
   * @param {Object} order - 订单信息
   * @param {Object} user - 用户信息
   * @param {string} previousStatus - 之前的状态
   * @returns {Object} 通知消息
   */
  generateOrderStatusMessage(order, user, previousStatus) {
    const statusMap = {
      active: '活跃',
      confirmed: '已确认',
      completed: '已完成',
      cancelled: '已取消'
    };

    const content = `【订单状态变更】
用户：${user.name}
订单编号：${order.id}
状态变更：${statusMap[previousStatus] || previousStatus} → ${statusMap[order.status] || order.status}
${order.selectedProvider ? `选择供应商：${order.selectedProvider}` : ''}
${order.selectedPrice ? `选择价格：¥${order.selectedPrice}` : ''}
变更时间：${new Date().toLocaleString('zh-CN')}`;

    return {
      msgtype: 'text',
      text: {
        content
      }
    };
  }

  /**
   * 发送通知到企业微信
   * @param {Object} message - 消息内容
   * @param {string} type - 通知类型
   * @param {Object} context - 上下文信息
   * @returns {Promise<Object>} 发送结果
   */
  async sendNotification(message, type, context = {}) {
    if (!this.webhookUrl) {
      this.logOperation('webhook_not_configured', { type, ...context }, 'warn');
      return {
        success: false,
        messageId: null,
        error: 'Webhook URL not configured'
      };
    }

    return await this.retry(async () => {
      const response = await fetch(this.webhookUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(message)
      });

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      const result = await response.json();

      if (result.errcode !== 0) {
        throw new Error(`WeChat API Error: ${result.errmsg} (code: ${result.errcode})`);
      }

      return {
        success: true,
        messageId: result.msgid || `msg_${Date.now()}`,
        response: result
      };
    }, this.retryAttempts, this.retryDelay);
  }

  /**
   * 批量发送通知
   * @param {Array} notifications - 通知列表
   * @returns {Promise<Object>} 批量发送结果
   */
  async sendBatchNotifications(notifications) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ notifications }, ['notifications']);

      if (!Array.isArray(notifications) || notifications.length === 0) {
        throw this.createBusinessError('通知列表不能为空');
      }

      // 使用并发处理优化批量发送性能
      const AsyncOptimizer = require('../utils/AsyncOptimizer');

      // 创建批量通知任务
      const batchTasks = notifications.map(notification => async () => {
        const result = await this.sendNotification(
          notification.message,
          notification.type || 'batch',
          notification.context || {}
        );

        return {
          ...notification,
          result,
          status: 'sent'
        };
      });

      // 并发执行批量任务
      const batchResult = await AsyncOptimizer.executeBatch(batchTasks, {
        maxConcurrency: 5, // 批量发送可以有更高的并发数
        retryAttempts: 3,
        retryDelay: 500,
        failFast: false
      });

      const results = batchResult.results;
      const errors = batchResult.errors.map((error, index) => ({
        ...notifications[error.index],
        error: error.error,
        status: 'failed'
      }));

      this.logOperation('batch_notifications_sent', {
        total: notifications.length,
        success: results.length,
        failed: errors.length
      });

      return this.buildResponse({
        results,
        errors,
        summary: {
          total: notifications.length,
          success: results.length,
          failed: errors.length
        }
      }, '批量通知发送完成');
    }, 'sendBatchNotifications', { count: notifications.length });
  }

  /**
   * 获取通知发送统计
   * @param {Object} filters - 过滤条件
   * @returns {Promise<Object>} 统计信息
   */
  async getNotificationStats(filters = {}) {
    return await this.handleAsyncOperation(async () => {
      // 这里可以从日志或数据库中获取统计信息
      // 目前返回模拟数据
      const stats = {
        total: 0,
        success: 0,
        failed: 0,
        byType: {},
        recentActivity: []
      };

      return this.buildResponse(stats, '获取通知统计成功');
    }, 'getNotificationStats', filters);
  }
}

module.exports = NotificationService;

/**
 * 订单业务逻辑服务
 * 处理订单相关的业务逻辑
 */

const BaseService = require('./BaseService');
const { orderRepo, quoteRepo } = require('../repositories');
const OrderIdService = require('./OrderIdService');

class OrderService extends BaseService {
  constructor() {
    super('OrderService');
    this.orderIdService = new OrderIdService();
    this.allowedSortFields = ['createdAt', 'updatedAt', 'status', 'selectedPrice'];
  }

  /**
   * 创建订单
   * @param {Object} orderData - 订单数据
   * @param {string} userId - 用户ID
   * @returns {Promise<Object>} 创建的订单
   */
  async createOrder(orderData, userId) {
    return await this.handleAsyncOperation(async () => {
      // 验证必需参数
      this.validateRequiredParams(orderData, ['warehouse', 'goods', 'deliveryAddress']);
      this.validateRequiredParams({ userId }, ['userId']);

      // 验证参数类型
      this.validateParamTypes(orderData, {
        warehouse: 'string',
        goods: 'string',
        deliveryAddress: 'string'
      });

      // 清理和标准化数据
      const cleanData = {
        warehouse: orderData.warehouse.trim(),
        goods: orderData.goods.trim(),
        deliveryAddress: orderData.deliveryAddress.trim()
      };

      // 验证数据长度
      if (cleanData.warehouse.length < 2 || cleanData.warehouse.length > 100) {
        throw this.createBusinessError('仓库名称长度必须在2-100字符之间');
      }

      if (cleanData.goods.length < 2 || cleanData.goods.length > 500) {
        throw this.createBusinessError('货物描述长度必须在2-500字符之间');
      }

      if (cleanData.deliveryAddress.length < 5 || cleanData.deliveryAddress.length > 200) {
        throw this.createBusinessError('配送地址长度必须在5-200字符之间');
      }

      // 在事务中创建订单
      const result = await orderRepo.transactionWithRetry(async (trx) => {
        // 生成订单ID
        const orderId = await this.orderIdService.generateOrderId();

        // 创建订单
        const newOrder = {
          id: orderId,
          ...cleanData,
          userId,
          status: 'active',
          createdAt: new Date().toISOString()
        };

        const createdOrder = await orderRepo.create(newOrder, trx);

        this.logOperation('order_created', {
          orderId: createdOrder.id,
          userId,
          warehouse: createdOrder.warehouse
        });

        return createdOrder;
      });

      return this.buildResponse(result, '订单创建成功');
    }, 'createOrder', { userId, warehouse: orderData.warehouse });
  }

  /**
   * 获取订单详情
   * @param {string} orderId - 订单ID
   * @param {string} userId - 用户ID
   * @param {string} userRole - 用户角色
   * @returns {Promise<Object>} 订单详情
   */
  async getOrderById(orderId, userId, userRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderId, userId, userRole }, ['orderId', 'userId', 'userRole']);

      // 检查访问权限
      const hasAccess = await orderRepo.checkUserAccess(orderId, userId, userRole);
      if (!hasAccess) {
        throw this.createBusinessError('无权访问此订单', 'ACCESS_DENIED', 403);
      }

      // 获取订单信息
      const order = await orderRepo.findById(orderId);
      if (!order) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      // 获取订单的报价信息
      const quotes = await quoteRepo.findByOrderId(orderId);

      const result = {
        ...order,
        quotes: quotes || []
      };

      return this.buildResponse(result, '获取订单详情成功');
    }, 'getOrderById', { orderId, userId });
  }

  /**
   * 获取用户订单列表
   * @param {string} userId - 用户ID
   * @param {Object} options - 查询选项
   * @returns {Promise<Object>} 订单列表
   */
  async getUserOrders(userId, options = {}) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ userId }, ['userId']);

      // 标准化分页参数
      const pagination = this.normalizePaginationParams(options);

      // 标准化排序参数
      const orderBy = this.normalizeOrderByParams(options.orderBy, this.allowedSortFields);

      // 构建查询选项
      const queryOptions = {
        status: options.status || null,
        limit: pagination.limit,
        offset: pagination.offset,
        orderBy: orderBy.length > 0 ? orderBy : [{ column: 'createdAt', direction: 'desc' }]
      };

      // 获取订单列表和总数
      const [orders, total] = await Promise.all([
        orderRepo.findByUserId(userId, queryOptions),
        orderRepo.count({ userId, ...(options.status && { status: options.status }) })
      ]);

      return this.buildPaginatedResponse(orders, total, pagination);
    }, 'getUserOrders', { userId, options });
  }

  /**
   * 更新订单
   * @param {string} orderId - 订单ID
   * @param {Object} updateData - 更新数据
   * @param {string} userId - 用户ID
   * @param {string} userRole - 用户角色
   * @returns {Promise<Object>} 更新后的订单
   */
  async updateOrder(orderId, updateData, userId, userRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderId, userId, userRole }, ['orderId', 'userId', 'userRole']);

      // 检查访问权限
      const hasAccess = await orderRepo.checkUserAccess(orderId, userId, userRole);
      if (!hasAccess) {
        throw this.createBusinessError('无权修改此订单', 'ACCESS_DENIED', 403);
      }

      // 获取现有订单
      const existingOrder = await orderRepo.findById(orderId);
      if (!existingOrder) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      // 检查订单状态是否允许修改
      if (existingOrder.status !== 'active') {
        throw this.createBusinessError('只能修改状态为活跃的订单', 'INVALID_ORDER_STATUS', 400);
      }

      // 验证和清理更新数据
      const allowedFields = ['warehouse', 'goods', 'deliveryAddress'];
      const cleanUpdateData = {};

      for (const field of allowedFields) {
        if (updateData[field] !== undefined) {
          if (typeof updateData[field] !== 'string') {
            throw this.createBusinessError(`${field} 必须是字符串类型`);
          }
          cleanUpdateData[field] = updateData[field].trim();
        }
      }

      if (Object.keys(cleanUpdateData).length === 0) {
        throw this.createBusinessError('没有提供有效的更新字段');
      }

      // 验证字段长度
      if (cleanUpdateData.warehouse && (cleanUpdateData.warehouse.length < 2 || cleanUpdateData.warehouse.length > 100)) {
        throw this.createBusinessError('仓库名称长度必须在2-100字符之间');
      }

      if (cleanUpdateData.goods && (cleanUpdateData.goods.length < 2 || cleanUpdateData.goods.length > 500)) {
        throw this.createBusinessError('货物描述长度必须在2-500字符之间');
      }

      if (cleanUpdateData.deliveryAddress && (cleanUpdateData.deliveryAddress.length < 5 || cleanUpdateData.deliveryAddress.length > 200)) {
        throw this.createBusinessError('配送地址长度必须在5-200字符之间');
      }

      // 更新订单
      const updatedOrder = await orderRepo.updateById(orderId, cleanUpdateData);

      this.logOperation('order_updated', {
        orderId,
        userId,
        updatedFields: Object.keys(cleanUpdateData)
      });

      return this.buildResponse(updatedOrder, '订单更新成功');
    }, 'updateOrder', { orderId, userId });
  }

  /**
   * 更新订单状态
   * @param {string} orderId - 订单ID
   * @param {string} status - 新状态
   * @param {string} userId - 用户ID
   * @param {string} userRole - 用户角色
   * @returns {Promise<Object>} 更新后的订单
   */
  async updateOrderStatus(orderId, status, userId, userRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderId, status, userId, userRole }, ['orderId', 'status', 'userId', 'userRole']);

      // 验证状态值
      const validStatuses = ['active', 'completed', 'cancelled'];
      if (!validStatuses.includes(status)) {
        throw this.createBusinessError('无效的订单状态', 'INVALID_STATUS', 400);
      }

      // 检查访问权限
      const hasAccess = await orderRepo.checkUserAccess(orderId, userId, userRole);
      if (!hasAccess) {
        throw this.createBusinessError('无权修改此订单', 'ACCESS_DENIED', 403);
      }

      // 获取现有订单
      const existingOrder = await orderRepo.findById(orderId);
      if (!existingOrder) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      // 检查状态转换是否合法
      if (existingOrder.status === status) {
        throw this.createBusinessError('订单状态未发生变化', 'NO_STATUS_CHANGE', 400);
      }

      // 更新订单状态
      const updatedOrder = await orderRepo.updateById(orderId, { status });

      this.logOperation('order_status_updated', {
        orderId,
        userId,
        oldStatus: existingOrder.status,
        newStatus: status
      });

      return this.buildResponse(updatedOrder, '订单状态更新成功');
    }, 'updateOrderStatus', { orderId, status, userId });
  }

  /**
   * 删除订单
   * @param {string} orderId - 订单ID
   * @param {string} userId - 用户ID
   * @param {string} userRole - 用户角色
   * @returns {Promise<Object>} 删除结果
   */
  async deleteOrder(orderId, userId, userRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderId, userId, userRole }, ['orderId', 'userId', 'userRole']);

      // 检查访问权限
      const hasAccess = await orderRepo.checkUserAccess(orderId, userId, userRole);
      if (!hasAccess) {
        throw this.createBusinessError('无权删除此订单', 'ACCESS_DENIED', 403);
      }

      // 获取现有订单
      const existingOrder = await orderRepo.findById(orderId);
      if (!existingOrder) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      // 检查订单状态是否允许删除
      if (existingOrder.status === 'completed') {
        throw this.createBusinessError('已完成的订单不能删除', 'CANNOT_DELETE_COMPLETED', 400);
      }

      // 删除订单
      await orderRepo.deleteById(orderId);

      this.logOperation('order_deleted', {
        orderId,
        userId,
        orderStatus: existingOrder.status
      });

      return this.buildResponse({
        deleted: true,
        orderId
      }, '订单删除成功');
    }, 'deleteOrder', { orderId, userId });
  }

  /**
   * 选择供应商
   * @param {string} orderId - 订单ID
   * @param {string} provider - 供应商名称
   * @param {string} userId - 用户ID
   * @param {string} userRole - 用户角色
   * @returns {Promise<Object>} 更新后的订单
   */
  async selectProvider(orderId, provider, userId, userRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderId, provider, userId, userRole }, ['orderId', 'provider', 'userId', 'userRole']);

      // 检查访问权限
      const hasAccess = await orderRepo.checkUserAccess(orderId, userId, userRole);
      if (!hasAccess) {
        throw this.createBusinessError('无权操作此订单', 'ACCESS_DENIED', 403);
      }

      // 获取订单和报价信息
      const [order, quote] = await Promise.all([
        orderRepo.findById(orderId),
        quoteRepo.findByOrderAndProvider(orderId, provider)
      ]);

      if (!order) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      if (!quote) {
        throw this.createBusinessError('报价不存在', 'QUOTE_NOT_FOUND', 404);
      }

      if (order.status !== 'active') {
        throw this.createBusinessError('只能为活跃状态的订单选择供应商', 'INVALID_ORDER_STATUS', 400);
      }

      // 更新订单选择的供应商
      const updatedOrder = await orderRepo.selectProvider(orderId, provider, quote.price);

      this.logOperation('provider_selected', {
        orderId,
        provider,
        price: quote.price,
        userId
      });

      return this.buildResponse(updatedOrder, '供应商选择成功');
    }, 'selectProvider', { orderId, provider, userId });
  }

  /**
   * 取消订单
   * @param {string} orderId - 订单ID
   * @param {string} reason - 取消原因
   * @param {string} userId - 用户ID
   * @param {string} userRole - 用户角色
   * @returns {Promise<Object>} 取消后的订单
   */
  async cancelOrder(orderId, reason, userId, userRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderId, userId, userRole }, ['orderId', 'userId', 'userRole']);

      // 检查访问权限
      const hasAccess = await orderRepo.checkUserAccess(orderId, userId, userRole);
      if (!hasAccess) {
        throw this.createBusinessError('无权取消此订单', 'ACCESS_DENIED', 403);
      }

      // 获取订单信息
      const order = await orderRepo.findById(orderId);
      if (!order) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      if (order.status === 'cancelled') {
        throw this.createBusinessError('订单已经被取消', 'ORDER_ALREADY_CANCELLED', 400);
      }

      if (order.status === 'completed') {
        throw this.createBusinessError('已完成的订单无法取消', 'CANNOT_CANCEL_COMPLETED_ORDER', 400);
      }

      // 取消订单
      const cancelledOrder = await orderRepo.cancelOrder(orderId, reason);

      this.logOperation('order_cancelled', {
        orderId,
        reason,
        userId,
        previousStatus: order.status
      });

      return this.buildResponse(cancelledOrder, '订单取消成功');
    }, 'cancelOrder', { orderId, userId });
  }

  /**
   * 获取订单统计信息
   * @param {string} userId - 用户ID（可选，管理员可以不传）
   * @param {string} userRole - 用户角色
   * @param {Object} filters - 过滤条件
   * @returns {Promise<Object>} 统计信息
   */
  async getOrderStats(userId, userRole, filters = {}) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ userRole }, ['userRole']);

      // 构建过滤条件
      const statsFilters = { ...filters };

      // 非管理员只能查看自己的统计
      if (userRole !== 'admin' && userId) {
        statsFilters.userId = userId;
      }

      const stats = await orderRepo.getOrderStats(statsFilters);

      return this.buildResponse(stats, '获取订单统计成功');
    }, 'getOrderStats', { userId, userRole });
  }

  /**
   * 搜索订单
   * @param {string} searchTerm - 搜索关键词
   * @param {string} userId - 用户ID
   * @param {string} userRole - 用户角色
   * @param {Object} options - 搜索选项
   * @returns {Promise<Object>} 搜索结果
   */
  async searchOrders(searchTerm, userId, userRole, options = {}) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ searchTerm, userId, userRole }, ['searchTerm', 'userId', 'userRole']);

      if (searchTerm.length < 2) {
        throw this.createBusinessError('搜索关键词至少需要2个字符');
      }

      // 标准化分页参数
      const pagination = this.normalizePaginationParams(options);

      // 构建搜索选项
      const searchOptions = {
        status: options.status || null,
        limit: pagination.limit,
        offset: pagination.offset
      };

      // 非管理员只能搜索自己的订单
      if (userRole !== 'admin') {
        searchOptions.userId = userId;
      }

      const orders = await orderRepo.searchOrders(searchTerm, searchOptions);

      return this.buildResponse(orders, '搜索完成', {
        searchTerm,
        resultCount: orders.length
      });
    }, 'searchOrders', { searchTerm, userId, userRole });
  }

  /**
   * 获取订单统计信息（管理员）
   * @returns {Promise<Object>} 统计信息
   */
  async getOrderStats() {
    return await this.handleAsyncOperation(async () => {
      const stats = await orderRepo.getGlobalStats();

      return this.buildResponse(stats, '获取订单统计成功');
    }, 'getOrderStats');
  }

  /**
   * 获取待处理订单列表（管理员功能）
   * @param {Object} options - 查询选项
   * @returns {Promise<Object>} 待处理订单列表
   */
  async getPendingOrders(options = {}) {
    return await this.handleAsyncOperation(async () => {
      // 标准化分页参数
      const pagination = this.normalizePaginationParams(options);

      // 标准化排序参数
      const orderBy = this.normalizeOrderByParams(options.orderBy, this.allowedSortFields);

      // 构建查询选项
      const queryOptions = {
        limit: pagination.limit,
        offset: pagination.offset,
        orderBy: orderBy.length > 0 ? orderBy : [{ column: 'createdAt', direction: 'asc' }]
      };

      // 获取待处理订单列表和总数
      const [orders, total] = await Promise.all([
        orderRepo.getPendingOrders(queryOptions),
        orderRepo.count({ status: 'active', selectedProvider: null })
      ]);

      return this.buildPaginatedResponse(orders, total, pagination, '获取待处理订单成功');
    }, 'getPendingOrders', { options });
  }

  /**
   * 批量操作订单（管理员功能）
   * @param {Array} orderIds - 订单ID列表
   * @param {string} operation - 操作类型 ('cancel', 'complete')
   * @param {string} adminId - 管理员ID
   * @returns {Promise<Object>} 批量操作结果
   */
  async batchUpdateOrders(orderIds, operation, adminId) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderIds, operation, adminId }, ['orderIds', 'operation', 'adminId']);

      if (!Array.isArray(orderIds) || orderIds.length === 0) {
        throw this.createBusinessError('订单ID列表不能为空');
      }

      const validOperations = ['cancel', 'complete'];
      if (!validOperations.includes(operation)) {
        throw this.createBusinessError('无效的批量操作类型');
      }

      // 使用事务确保数据一致性
      const results = await this.executeInTransaction(async (trx) => {
        const processedResults = {
          processed: 0,
          success: 0,
          failed: 0,
          errors: []
        };

        for (const orderId of orderIds) {
          try {
            processedResults.processed++;

            // 验证订单存在且状态允许操作
            const order = await orderRepo.findById(orderId, trx);
            if (!order) {
              processedResults.failed++;
              processedResults.errors.push({
                orderId,
                error: '订单不存在'
              });
              continue;
            }

            if (order.status === 'cancelled' || order.status === 'completed') {
              processedResults.failed++;
              processedResults.errors.push({
                orderId,
                error: '订单状态不允许此操作'
              });
              continue;
            }

            // 执行状态更新
            const newStatus = operation === 'cancel' ? 'cancelled' : 'completed';
            await orderRepo.updateById(orderId, {
              status: newStatus,
              updatedAt: new Date().toISOString()
            }, trx);

            processedResults.success++;

            this.logOperation('batch_order_updated', {
              orderId,
              operation,
              newStatus,
              adminId
            });

          } catch (error) {
            processedResults.failed++;
            processedResults.errors.push({
              orderId,
              error: error.message
            });
            this.logger.error('批量操作单个订单失败', {
              orderId,
              operation,
              error: error.message
            });
          }
        }

        return processedResults;
      });

      this.logOperation('batch_orders_completed', {
        totalOrders: orderIds.length,
        operation,
        results,
        adminId
      });

      return this.buildResponse(results, '批量操作完成');
    }, 'batchUpdateOrders', { orderIds, operation, adminId });
  }

  /**
   * 导出订单数据（管理员功能）
   * @param {Object} filters - 过滤条件
   * @param {string} format - 导出格式 ('csv', 'excel')
   * @returns {Promise<Object>} 导出结果
   */
  async exportOrders(filters = {}, format = 'csv') {
    return await this.handleAsyncOperation(async () => {
      const validFormats = ['csv', 'excel'];
      if (!validFormats.includes(format)) {
        throw this.createBusinessError('不支持的导出格式');
      }

      // 构建查询条件
      const queryOptions = {
        status: filters.status || null,
        startDate: filters.startDate || null,
        endDate: filters.endDate || null
      };

      // 获取要导出的订单数据
      const orders = await orderRepo.findForExport(queryOptions);

      // 生成导出文件名
      const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
      const fileName = `orders_export_${timestamp}.${format}`;
      const downloadUrl = `/api/downloads/${fileName}`;

      // 这里可以实现实际的文件生成逻辑
      // 目前先返回文件信息，实际文件生成可以异步处理
      const exportInfo = {
        downloadUrl,
        fileName,
        format,
        recordCount: orders.length,
        expiresAt: new Date(Date.now() + 3600000).toISOString(), // 1小时后过期
        filters: queryOptions
      };

      this.logOperation('orders_export_created', {
        fileName,
        format,
        recordCount: orders.length,
        filters: queryOptions
      });

      return this.buildResponse(exportInfo, '订单导出任务已创建');
    }, 'exportOrders', { filters, format });
  }
}

module.exports = OrderService;

/**
 * 报价业务逻辑服务
 * 处理报价相关的业务逻辑
 */

const BaseService = require('./BaseService');
const { quoteRepo, orderRepo, providerRepo } = require('../repositories');

class QuoteService extends BaseService {
  constructor() {
    super('QuoteService');
    this.allowedSortFields = ['price', 'createdAt', 'estimatedDelivery'];
  }

  /**
   * 创建或更新报价
   * @param {string} orderId - 订单ID
   * @param {string} provider - 供应商名称
   * @param {Object} quoteData - 报价数据
   * @param {string} accessKey - 供应商访问密钥
   * @returns {Promise<Object>} 创建或更新的报价
   */
  async createOrUpdateQuote(orderId, provider, quoteData, accessKey) {
    return await this.handleAsyncOperation(async () => {
      // 验证必需参数
      this.validateRequiredParams({ orderId, provider, accessKey }, ['orderId', 'provider', 'accessKey']);
      this.validateRequiredParams(quoteData, ['price', 'estimatedDelivery']);

      // 验证参数类型
      this.validateParamTypes(quoteData, {
        price: 'number',
        estimatedDelivery: 'string'
      });

      // 验证供应商访问权限
      const providerInfo = await providerRepo.validateAccess(accessKey);
      if (!providerInfo) {
        throw this.createBusinessError('无效的访问密钥', 'INVALID_ACCESS_KEY', 401);
      }

      if (providerInfo.name !== provider) {
        throw this.createBusinessError('供应商名称与访问密钥不匹配', 'PROVIDER_MISMATCH', 403);
      }

      // 验证订单是否存在且状态有效
      const order = await orderRepo.findById(orderId);
      if (!order) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      if (order.status !== 'active') {
        throw this.createBusinessError('只能为活跃状态的订单提供报价', 'INVALID_ORDER_STATUS', 400);
      }

      // 验证报价数据
      if (quoteData.price <= 0) {
        throw this.createBusinessError('报价金额必须大于0');
      }

      if (quoteData.price > 999999.99) {
        throw this.createBusinessError('报价金额不能超过999999.99');
      }

      // 验证预计送达时间格式
      const deliveryDate = new Date(quoteData.estimatedDelivery);
      if (isNaN(deliveryDate.getTime())) {
        throw this.createBusinessError('预计送达时间格式无效');
      }

      if (deliveryDate <= new Date()) {
        throw this.createBusinessError('预计送达时间必须是未来时间');
      }

      // 清理和标准化数据
      const cleanQuoteData = {
        price: parseFloat(quoteData.price.toFixed(2)),
        estimatedDelivery: deliveryDate.toISOString(),
        remarks: quoteData.remarks ? quoteData.remarks.trim() : null
      };

      // 创建或更新报价
      const quote = await quoteRepo.upsertQuote(orderId, provider, cleanQuoteData);

      this.logOperation('quote_created_or_updated', {
        orderId,
        provider,
        price: cleanQuoteData.price,
        quoteId: quote.id
      });

      return this.buildResponse(quote, '报价提交成功');
    }, 'createOrUpdateQuote', { orderId, provider });
  }

  /**
   * 获取订单的所有报价
   * @param {string} orderId - 订单ID
   * @param {Object} options - 查询选项
   * @returns {Promise<Object>} 报价列表
   */
  async getOrderQuotes(orderId, options = {}) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderId }, ['orderId']);

      // 验证订单是否存在
      const order = await orderRepo.findById(orderId);
      if (!order) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      // 标准化排序参数
      const orderBy = this.normalizeOrderByParams(options.orderBy, this.allowedSortFields);

      // 构建查询选项
      const queryOptions = {
        orderBy: orderBy.length > 0 ? orderBy : [{ column: 'price', direction: 'asc' }]
      };

      // 获取报价列表和统计信息
      const [quotes, stats] = await Promise.all([
        quoteRepo.findByOrderId(orderId, queryOptions),
        quoteRepo.getQuoteStats(orderId)
      ]);

      const result = {
        order: {
          id: order.id,
          warehouse: order.warehouse,
          goods: order.goods,
          deliveryAddress: order.deliveryAddress,
          status: order.status,
          selectedProvider: order.selectedProvider,
          selectedPrice: order.selectedPrice
        },
        quotes,
        stats
      };

      return this.buildResponse(result, '获取报价列表成功');
    }, 'getOrderQuotes', { orderId });
  }

  /**
   * 获取供应商的报价历史
   * @param {string} provider - 供应商名称
   * @param {string} accessKey - 访问密钥
   * @param {Object} options - 查询选项
   * @returns {Promise<Object>} 报价历史
   */
  async getProviderQuotes(provider, accessKey, options = {}) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ provider, accessKey }, ['provider', 'accessKey']);

      // 验证供应商访问权限
      const providerInfo = await providerRepo.validateAccess(accessKey);
      if (!providerInfo || providerInfo.name !== provider) {
        throw this.createBusinessError('无权访问', 'ACCESS_DENIED', 403);
      }

      // 标准化分页参数
      const pagination = this.normalizePaginationParams(options);

      // 标准化排序参数
      const orderBy = this.normalizeOrderByParams(options.orderBy, this.allowedSortFields);

      // 构建查询选项
      const queryOptions = {
        limit: pagination.limit,
        offset: pagination.offset,
        orderBy: orderBy.length > 0 ? orderBy : [{ column: 'createdAt', direction: 'desc' }],
        startDate: options.startDate || null,
        endDate: options.endDate || null
      };

      // 获取报价列表和统计信息
      const [quotes, stats] = await Promise.all([
        quoteRepo.findByProvider(provider, queryOptions),
        quoteRepo.getProviderStats(provider, {
          startDate: options.startDate,
          endDate: options.endDate
        })
      ]);

      const result = {
        provider: providerInfo.name,
        quotes,
        stats
      };

      return this.buildPaginatedResponse(result, stats.totalQuotes, pagination);
    }, 'getProviderQuotes', { provider });
  }

  /**
   * 获取报价详情
   * @param {string} quoteId - 报价ID
   * @param {string} userId - 用户ID
   * @param {string} userRole - 用户角色
   * @returns {Promise<Object>} 报价详情
   */
  async getQuoteById(quoteId, userId, userRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ quoteId, userId, userRole }, ['quoteId', 'userId', 'userRole']);

      const quote = await quoteRepo.findById(quoteId);
      if (!quote) {
        throw this.createBusinessError('报价不存在', 'QUOTE_NOT_FOUND', 404);
      }

      // 检查访问权限
      if (userRole !== 'admin') {
        const order = await orderRepo.findById(quote.orderId);
        if (!order || order.userId !== userId) {
          throw this.createBusinessError('无权查看此报价', 'ACCESS_DENIED', 403);
        }
      }

      return this.buildResponse(quote, '获取报价详情成功');
    }, 'getQuoteById', { quoteId, userId });
  }

  /**
   * 用户选择报价
   * @param {string} quoteId - 报价ID
   * @param {string} userId - 用户ID
   * @param {string} userRole - 用户角色
   * @returns {Promise<Object>} 选择结果
   */
  async selectQuote(quoteId, userId, userRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ quoteId, userId, userRole }, ['quoteId', 'userId', 'userRole']);

      const quote = await quoteRepo.findById(quoteId);
      if (!quote) {
        throw this.createBusinessError('报价不存在', 'QUOTE_NOT_FOUND', 404);
      }

      // 检查访问权限
      const order = await orderRepo.findById(quote.orderId);
      if (!order) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      if (userRole !== 'admin' && order.userId !== userId) {
        throw this.createBusinessError('无权选择此报价', 'ACCESS_DENIED', 403);
      }

      // 更新订单状态为已选择供应商
      await orderRepo.updateById(quote.orderId, {
        selectedProvider: quote.provider,
        selectedQuoteId: quoteId,
        status: 'in_progress'
      });

      this.logOperation('quote_selected', {
        quoteId,
        orderId: quote.orderId,
        provider: quote.provider,
        userId
      });

      return this.buildResponse({
        quote,
        order: { ...order, selectedProvider: quote.provider, selectedQuoteId: quoteId }
      }, '报价选择成功');
    }, 'selectQuote', { quoteId, userId });
  }

  /**
   * 供应商更新报价
   * @param {string} quoteId - 报价ID
   * @param {Object} updateData - 更新数据
   * @param {string} provider - 供应商名称
   * @param {string} accessKey - 访问密钥
   * @returns {Promise<Object>} 更新结果
   */
  async updateQuote(quoteId, updateData, provider, accessKey) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ quoteId, provider, accessKey }, ['quoteId', 'provider', 'accessKey']);

      // 验证供应商访问权限
      const providerInfo = await providerRepo.validateAccess(accessKey);
      if (!providerInfo || providerInfo.name !== provider) {
        throw this.createBusinessError('无权访问', 'ACCESS_DENIED', 403);
      }

      const quote = await quoteRepo.findById(quoteId);
      if (!quote) {
        throw this.createBusinessError('报价不存在', 'QUOTE_NOT_FOUND', 404);
      }

      if (quote.provider !== provider) {
        throw this.createBusinessError('无权修改此报价', 'ACCESS_DENIED', 403);
      }

      // 清理和验证更新数据
      const cleanUpdateData = this.sanitizeData(updateData);

      if (cleanUpdateData.price !== undefined) {
        if (typeof cleanUpdateData.price !== 'number' || cleanUpdateData.price <= 0) {
          throw this.createBusinessError('价格格式无效');
        }
      }

      if (cleanUpdateData.estimatedDelivery !== undefined) {
        const deliveryDate = new Date(cleanUpdateData.estimatedDelivery);
        if (isNaN(deliveryDate.getTime()) || deliveryDate <= new Date()) {
          throw this.createBusinessError('预计送达时间无效');
        }
      }

      // 更新报价
      const updatedQuote = await quoteRepo.updateById(quoteId, cleanUpdateData);

      this.logOperation('quote_updated', {
        quoteId,
        provider,
        updatedFields: Object.keys(cleanUpdateData)
      });

      return this.buildResponse(updatedQuote, '报价更新成功');
    }, 'updateQuote', { quoteId, provider });
  }

  /**
   * 供应商撤回报价
   * @param {string} quoteId - 报价ID
   * @param {string} provider - 供应商名称
   * @param {string} accessKey - 访问密钥
   * @returns {Promise<Object>} 撤回结果
   */
  async withdrawQuote(quoteId, provider, accessKey) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ quoteId, provider, accessKey }, ['quoteId', 'provider', 'accessKey']);

      // 验证供应商访问权限
      const providerInfo = await providerRepo.validateAccess(accessKey);
      if (!providerInfo || providerInfo.name !== provider) {
        throw this.createBusinessError('无权访问', 'ACCESS_DENIED', 403);
      }

      const quote = await quoteRepo.findById(quoteId);
      if (!quote) {
        throw this.createBusinessError('报价不存在', 'QUOTE_NOT_FOUND', 404);
      }

      if (quote.provider !== provider) {
        throw this.createBusinessError('无权撤回此报价', 'ACCESS_DENIED', 403);
      }

      // 检查报价是否已被选择
      const order = await orderRepo.findById(quote.orderId);
      if (order && order.selectedQuoteId === quoteId) {
        throw this.createBusinessError('已被选择的报价不能撤回', 'QUOTE_SELECTED', 400);
      }

      // 删除报价
      await quoteRepo.deleteById(quoteId);

      this.logOperation('quote_withdrawn', {
        quoteId,
        orderId: quote.orderId,
        provider
      });

      return this.buildResponse({
        withdrawn: true,
        quoteId
      }, '报价撤回成功');
    }, 'withdrawQuote', { quoteId, provider });
  }

  /**
   * 获取所有报价（管理员）
   * @param {Object} options - 查询选项
   * @returns {Promise<Object>} 报价列表
   */
  async getAllQuotes(options = {}) {
    return await this.handleAsyncOperation(async () => {
      // 标准化分页参数
      const pagination = this.normalizePaginationParams(options);

      // 标准化排序参数
      const orderBy = this.normalizeOrderByParams(options.orderBy, this.allowedSortFields);

      // 构建查询选项
      const queryOptions = {
        limit: pagination.limit,
        offset: pagination.offset,
        orderBy: orderBy.length > 0 ? orderBy : [{ column: 'createdAt', direction: 'desc' }],
        startDate: options.startDate || null,
        endDate: options.endDate || null
      };

      // 获取报价列表和总数
      const [quotes, totalCount] = await Promise.all([
        quoteRepo.findAll(queryOptions),
        quoteRepo.countAll(queryOptions)
      ]);

      return this.buildPaginatedResponse(quotes, totalCount, pagination);
    }, 'getAllQuotes', { options });
  }

  /**
   * 获取报价统计信息（管理员）
   * @returns {Promise<Object>} 统计信息
   */
  async getQuoteStats() {
    return await this.handleAsyncOperation(async () => {
      const stats = await quoteRepo.getGlobalStats();

      return this.buildResponse(stats, '获取报价统计成功');
    }, 'getQuoteStats');
  }

  /**
   * 删除报价
   * @param {string} orderId - 订单ID
   * @param {string} provider - 供应商名称
   * @param {string} accessKey - 访问密钥
   * @returns {Promise<Object>} 删除结果
   */
  async deleteQuote(orderId, provider, accessKey) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderId, provider, accessKey }, ['orderId', 'provider', 'accessKey']);

      // 验证供应商访问权限
      const providerInfo = await providerRepo.validateAccess(accessKey);
      if (!providerInfo || providerInfo.name !== provider) {
        throw this.createBusinessError('无权访问', 'ACCESS_DENIED', 403);
      }

      // 验证报价是否存在
      const quote = await quoteRepo.findByOrderAndProvider(orderId, provider);
      if (!quote) {
        throw this.createBusinessError('报价不存在', 'QUOTE_NOT_FOUND', 404);
      }

      // 检查订单状态
      const order = await orderRepo.findById(orderId);
      if (order && order.selectedProvider === provider) {
        throw this.createBusinessError('无法删除已被选中的报价', 'CANNOT_DELETE_SELECTED_QUOTE', 400);
      }

      // 删除报价
      const deleted = await quoteRepo.deleteById(quote.id);
      if (!deleted) {
        throw this.createBusinessError('删除报价失败', 'DELETE_FAILED', 500);
      }

      this.logOperation('quote_deleted', {
        orderId,
        provider,
        quoteId: quote.id,
        price: quote.price
      });

      return this.buildResponse(null, '报价删除成功');
    }, 'deleteQuote', { orderId, provider });
  }

  /**
   * 获取最低报价
   * @param {string} orderId - 订单ID
   * @returns {Promise<Object>} 最低报价信息
   */
  async getLowestQuote(orderId) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderId }, ['orderId']);

      // 验证订单是否存在
      const order = await orderRepo.findById(orderId);
      if (!order) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      const lowestQuote = await quoteRepo.getLowestQuote(orderId);

      return this.buildResponse(lowestQuote, '获取最低报价成功');
    }, 'getLowestQuote', { orderId });
  }

  /**
   * 获取价格范围内的报价
   * @param {string} orderId - 订单ID
   * @param {number} minPrice - 最低价格
   * @param {number} maxPrice - 最高价格
   * @returns {Promise<Object>} 价格范围内的报价
   */
  async getQuotesByPriceRange(orderId, minPrice, maxPrice) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderId, minPrice, maxPrice }, ['orderId', 'minPrice', 'maxPrice']);
      this.validateParamTypes({ minPrice, maxPrice }, { minPrice: 'number', maxPrice: 'number' });

      if (minPrice < 0 || maxPrice < 0) {
        throw this.createBusinessError('价格不能为负数');
      }

      if (minPrice > maxPrice) {
        throw this.createBusinessError('最低价格不能大于最高价格');
      }

      // 验证订单是否存在
      const order = await orderRepo.findById(orderId);
      if (!order) {
        throw this.createBusinessError('订单不存在', 'ORDER_NOT_FOUND', 404);
      }

      const quotes = await quoteRepo.findByPriceRange(orderId, minPrice, maxPrice);

      return this.buildResponse(quotes, '获取价格范围报价成功', {
        priceRange: { minPrice, maxPrice },
        resultCount: quotes.length
      });
    }, 'getQuotesByPriceRange', { orderId, minPrice, maxPrice });
  }

  /**
   * 获取报价统计信息（管理员功能）
   * @param {Object} filters - 过滤条件
   * @returns {Promise<Object>} 报价统计信息
   */
  async getQuoteStatsAdmin(filters = {}) {
    return await this.handleAsyncOperation(async () => {
      const {
        startDate = null,
        endDate = null,
        provider = null
      } = filters;

      // 构建查询条件
      const queryOptions = {
        startDate,
        endDate,
        provider
      };

      // 获取统计数据
      const [
        totalStats,
        providerStats,
        priceStats,
        timeSeriesData
      ] = await Promise.all([
        quoteRepo.getTotalStats(queryOptions),
        quoteRepo.getProviderStats(queryOptions),
        quoteRepo.getPriceStats(queryOptions),
        quoteRepo.getTimeSeriesData(queryOptions)
      ]);

      const result = {
        totalQuotes: totalStats.totalQuotes || 0,
        totalOrders: totalStats.totalOrders || 0,
        averageQuotesPerOrder: totalStats.totalOrders > 0
          ? (totalStats.totalQuotes / totalStats.totalOrders).toFixed(2)
          : 0,
        priceStats: {
          min: priceStats.minPrice || 0,
          max: priceStats.maxPrice || 0,
          avg: priceStats.avgPrice || 0,
          median: priceStats.medianPrice || 0
        },
        providerStats: providerStats || [],
        timeSeriesData: timeSeriesData || []
      };

      return this.buildResponse(result, '获取报价统计成功');
    }, 'getQuoteStatsAdmin', { filters });
  }

  /**
   * 导出报价数据（管理员功能）
   * @param {Object} filters - 过滤条件
   * @param {string} format - 导出格式 ('csv', 'excel')
   * @returns {Promise<Object>} 导出结果
   */
  async exportQuotes(filters = {}, format = 'csv') {
    return await this.handleAsyncOperation(async () => {
      const validFormats = ['csv', 'excel'];
      if (!validFormats.includes(format)) {
        throw this.createBusinessError('不支持的导出格式');
      }

      // 构建查询条件
      const queryOptions = {
        startDate: filters.startDate || null,
        endDate: filters.endDate || null,
        provider: filters.provider || null,
        orderId: filters.orderId || null
      };

      // 获取要导出的报价数据
      const quotes = await quoteRepo.findForExport(queryOptions);

      // 生成导出文件名
      const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
      const fileName = `quotes_export_${timestamp}.${format}`;
      const downloadUrl = `/api/downloads/${fileName}`;

      // 导出信息
      const exportInfo = {
        downloadUrl,
        fileName,
        format,
        recordCount: quotes.length,
        expiresAt: new Date(Date.now() + 3600000).toISOString(), // 1小时后过期
        filters: queryOptions
      };

      this.logOperation('quotes_export_created', {
        fileName,
        format,
        recordCount: quotes.length,
        filters: queryOptions
      });

      return this.buildResponse(exportInfo, '报价导出任务已创建');
    }, 'exportQuotes', { filters, format });
  }

  /**
   * 批量获取多个订单的报价（管理员功能）
   * @param {Array} orderIds - 订单ID列表
   * @returns {Promise<Object>} 批量报价结果
   */
  async getBatchQuotes(orderIds) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ orderIds }, ['orderIds']);

      if (!Array.isArray(orderIds) || orderIds.length === 0) {
        throw this.createBusinessError('订单ID列表不能为空');
      }

      if (orderIds.length > 100) {
        throw this.createBusinessError('一次最多只能查询100个订单的报价');
      }

      // 批量获取报价数据
      const batchResults = await Promise.all(
        orderIds.map(async (orderId) => {
          try {
            // 获取订单的所有报价
            const quotes = await quoteRepo.findByOrderId(orderId);

            // 计算统计信息
            const stats = {
              count: quotes.length,
              minPrice: quotes.length > 0 ? Math.min(...quotes.map(q => q.price)) : 0,
              maxPrice: quotes.length > 0 ? Math.max(...quotes.map(q => q.price)) : 0,
              avgPrice: quotes.length > 0
                ? (quotes.reduce((sum, q) => sum + q.price, 0) / quotes.length).toFixed(2)
                : 0
            };

            return {
              orderId,
              quotes,
              stats
            };
          } catch (error) {
            this.logger.error('获取单个订单报价失败', {
              orderId,
              error: error.message
            });

            return {
              orderId,
              quotes: [],
              stats: { count: 0, minPrice: 0, maxPrice: 0, avgPrice: 0 },
              error: error.message
            };
          }
        })
      );

      return this.buildResponse(batchResults, '批量获取报价完成');
    }, 'getBatchQuotes', { orderIds });
  }
}

module.exports = QuoteService;

/**
 * 用户业务逻辑服务
 * 处理用户相关的业务逻辑
 */

const BaseService = require('./BaseService');
const { userRepo } = require('../repositories');
const PasswordHistoryRepository = require('../repositories/PasswordHistoryRepository');
const passwordPolicy = require('../utils/PasswordPolicy');
const jwt = require('jsonwebtoken');
const config = require('../config/env');
const { logger } = require('../config/logger');
const bcrypt = require('bcryptjs');

class UserService extends BaseService {
  constructor() {
    super('UserService');
    this.allowedSortFields = ['created_at', 'updated_at', 'username', 'email'];
    this.passwordRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{8,}$/;
    this.emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    this.passwordHistoryRepo = new PasswordHistoryRepository();
  }

  /**
   * 用户注册
   * @param {Object} userData - 用户数据
   * @returns {Promise<Object>} 注册结果
   */
  async registerUser(userData) {
    return await this.handleAsyncOperation(async () => {
      // 验证必需参数
      this.validateRequiredParams(userData, ['email', 'password', 'username']);

      // 验证参数类型
      this.validateParamTypes(userData, {
        email: 'string',
        password: 'string',
        username: 'string'
      });

      // 清理和标准化数据
      const cleanData = {
        email: userData.email.trim().toLowerCase(),
        password: userData.password,
        username: userData.username.trim(),
        role: userData.role || 'user'
      };

      // 验证邮箱格式
      if (!this.emailRegex.test(cleanData.email)) {
        throw this.createBusinessError('邮箱格式无效');
      }

      // 使用新的密码策略验证密码强度
      const passwordValidation = passwordPolicy.validatePassword(cleanData.password, {
        username: cleanData.username,
        email: cleanData.email
      });

      if (!passwordValidation.isValid) {
        const errorMessage = passwordValidation.errors.join('; ');
        throw this.createBusinessError(`密码不符合安全要求: ${errorMessage}`);
      }

      // 记录密码强度信息
      this.logOperation('password_strength_check', {
        userId: 'new_user',
        strength: passwordPolicy.getStrengthDescription(passwordValidation.strength),
        score: passwordValidation.score
      });

      // 验证用户名长度
      if (cleanData.username.length < 2 || cleanData.username.length > 50) {
        throw this.createBusinessError('用户名长度必须在2-50字符之间');
      }

      // 验证角色
      const validRoles = ['user', 'admin'];
      if (!validRoles.includes(cleanData.role)) {
        throw this.createBusinessError('无效的用户角色');
      }

      // 创建用户
      const newUser = await userRepo.createUser(cleanData);

      this.logOperation('user_registered', {
        userId: newUser.id,
        email: newUser.email,
        role: newUser.role
      });

      // 生成JWT令牌
      const token = this.generateToken(newUser);

      return this.buildResponse({
        user: newUser,
        token
      }, '用户注册成功');
    }, 'registerUser', { email: userData.email });
  }

  /**
   * 用户登录
   * @param {string} email - 邮箱
   * @param {string} password - 密码
   * @returns {Promise<Object>} 登录结果
   */
  async loginUser(email, password) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ email, password }, ['email', 'password']);

      const cleanEmail = email.trim().toLowerCase();

      // 验证用户凭据
      const user = await userRepo.validateUser(cleanEmail, password);
      if (!user) {
        throw this.createBusinessError('邮箱或密码错误', 'INVALID_CREDENTIALS', 401);
      }

      this.logOperation('user_logged_in', {
        userId: user.id,
        email: user.email
      });

      // 生成JWT令牌
      const token = this.generateToken(user);

      return this.buildResponse({
        user,
        token
      }, '登录成功');
    }, 'loginUser', { email });
  }

  /**
   * 刷新用户token
   * @param {string} userId - 用户ID
   * @returns {Promise<Object>} 新的token
   */
  async refreshToken(userId) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ userId }, ['userId']);

      const user = await userRepo.findById(userId);
      if (!user) {
        throw this.createBusinessError('用户不存在', 'USER_NOT_FOUND', 404);
      }

      if (!user.isActive) {
        throw this.createBusinessError('用户已被禁用', 'USER_DISABLED', 403);
      }

      this.logOperation('token_refreshed', {
        userId: user.id,
        email: user.email
      });

      // 生成新的JWT令牌
      const token = this.generateToken(user);

      return this.buildResponse({
        token,
        user: this.sanitizeData(user)
      }, 'Token刷新成功');
    }, 'refreshToken', { userId });
  }

  /**
   * 用户登出
   * @param {string} userId - 用户ID
   * @returns {Promise<Object>} 登出结果
   */
  async logout(userId) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ userId }, ['userId']);

      this.logOperation('user_logged_out', {
        userId
      });

      // 在实际应用中，这里可以将token加入黑名单
      // 或者在Redis中记录已登出的token

      return this.buildResponse({
        loggedOut: true,
        timestamp: new Date().toISOString()
      }, '登出成功');
    }, 'logout', { userId });
  }

  /**
   * 获取用户信息
   * @param {string} userId - 用户ID
   * @returns {Promise<Object>} 用户信息
   */
  async getUserById(userId) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ userId }, ['userId']);

      const user = await userRepo.findById(userId);
      if (!user) {
        throw this.createBusinessError('用户不存在', 'USER_NOT_FOUND', 404);
      }

      // 清理敏感数据
      const sanitizedUser = this.sanitizeData(user);

      return this.buildResponse(sanitizedUser, '获取用户信息成功');
    }, 'getUserById', { userId });
  }

  /**
   * 更新用户信息
   * @param {string} userId - 用户ID
   * @param {Object} updateData - 更新数据
   * @param {string} currentUserRole - 当前用户角色
   * @returns {Promise<Object>} 更新后的用户信息
   */
  async updateUser(userId, updateData, currentUserRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ userId, currentUserRole }, ['userId', 'currentUserRole']);

      // 获取现有用户
      const existingUser = await userRepo.findById(userId);
      if (!existingUser) {
        throw this.createBusinessError('用户不存在', 'USER_NOT_FOUND', 404);
      }

      // 验证和清理更新数据
      const allowedFields = ['name', 'email'];
      if (currentUserRole === 'admin') {
        allowedFields.push('role', 'isActive');
      }

      const cleanUpdateData = {};
      for (const field of allowedFields) {
        if (updateData[field] !== undefined) {
          cleanUpdateData[field] = updateData[field];
        }
      }

      if (Object.keys(cleanUpdateData).length === 0) {
        throw this.createBusinessError('没有提供有效的更新字段');
      }

      // 验证字段
      if (cleanUpdateData.email) {
        cleanUpdateData.email = cleanUpdateData.email.trim().toLowerCase();
        if (!this.emailRegex.test(cleanUpdateData.email)) {
          throw this.createBusinessError('邮箱格式无效');
        }
      }

      if (cleanUpdateData.name) {
        cleanUpdateData.name = cleanUpdateData.name.trim();
        if (cleanUpdateData.name.length < 2 || cleanUpdateData.name.length > 50) {
          throw this.createBusinessError('用户名长度必须在2-50字符之间');
        }
      }

      if (cleanUpdateData.role) {
        const validRoles = ['user', 'admin'];
        if (!validRoles.includes(cleanUpdateData.role)) {
          throw this.createBusinessError('无效的用户角色');
        }
      }

      // 更新用户
      const updatedUser = await userRepo.updateUser(userId, cleanUpdateData);

      this.logOperation('user_updated', {
        userId,
        updatedFields: Object.keys(cleanUpdateData),
        updatedBy: currentUserRole
      });

      return this.buildResponse(updatedUser, '用户信息更新成功');
    }, 'updateUser', { userId });
  }

  /**
   * 更改密码
   * @param {string} userId - 用户ID
   * @param {string} currentPassword - 当前密码
   * @param {string} newPassword - 新密码
   * @returns {Promise<Object>} 更新结果
   */
  async changePassword(userId, currentPassword, newPassword) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ userId, currentPassword, newPassword }, ['userId', 'currentPassword', 'newPassword']);

      // 获取用户信息
      const user = await userRepo.findById(userId);
      if (!user) {
        throw this.createBusinessError('用户不存在', 'USER_NOT_FOUND', 404);
      }

      // 验证当前密码
      const isValidCurrentPassword = await userRepo.validateUser(user.email, currentPassword);
      if (!isValidCurrentPassword) {
        throw this.createBusinessError('当前密码错误', 'INVALID_CURRENT_PASSWORD', 400);
      }

      // 使用新的密码策略验证新密码强度
      const passwordValidation = passwordPolicy.validatePassword(newPassword, {
        name: user.name,
        email: user.email
      });

      if (!passwordValidation.isValid) {
        const errorMessage = passwordValidation.errors.join('; ');
        throw this.createBusinessError(`新密码不符合安全要求: ${errorMessage}`);
      }

      // 检查新密码是否与当前密码相同
      if (currentPassword === newPassword) {
        throw this.createBusinessError('新密码不能与当前密码相同');
      }

      // 检查密码历史记录
      const passwordHistory = await this.passwordHistoryRepo.getRecentPasswordHashes(userId, 5);
      const isRepeatedPassword = await passwordPolicy.checkPasswordHistory(newPassword, passwordHistory);

      if (isRepeatedPassword) {
        throw this.createBusinessError('新密码不能与最近使用过的密码相同，请选择一个全新的密码');
      }

      // 在事务中更新密码并保存历史记录
      const result = await this.executeInTransaction(async (trx) => {
        // 获取当前密码哈希用于历史记录
        const currentPasswordHash = await bcrypt.hash(newPassword, 12);

        // 更新密码
        const success = await userRepo.updatePassword(userId, newPassword, trx);
        if (!success) {
          throw this.createBusinessError('密码更新失败', 'PASSWORD_UPDATE_FAILED', 500);
        }

        // 保存密码历史记录
        await this.passwordHistoryRepo.addPasswordHistory(
          userId,
          currentPasswordHash,
          null, // IP地址可以从请求上下文获取
          trx
        );

        // 更新用户的密码相关字段
        await userRepo.updateById(userId, {
          password_changed_at: new Date(),
          password_expired: false,
          force_password_change: false,
          failed_login_attempts: 0
        }, trx);

        return true;
      });

      this.logOperation('password_changed', {
        userId,
        email: user.email,
        strength: passwordPolicy.getStrengthDescription(passwordValidation.strength)
      });

      return this.buildResponse(null, '密码更改成功');
    }, 'changePassword', { userId });
  }

  /**
   * 获取用户列表（管理员功能）
   * @param {string} currentUserRole - 当前用户角色
   * @param {Object} options - 查询选项
   * @returns {Promise<Object>} 用户列表
   */
  async getUserList(currentUserRole, options = {}) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ currentUserRole }, ['currentUserRole']);

      if (currentUserRole !== 'admin') {
        throw this.createBusinessError('无权访问用户列表', 'ACCESS_DENIED', 403);
      }

      // 标准化分页参数
      const pagination = this.normalizePaginationParams(options);

      // 标准化排序参数
      const orderBy = this.normalizeOrderByParams(options.orderBy, this.allowedSortFields);

      // 构建查询选项
      const queryOptions = {
        role: options.role || null,
        isActive: options.isActive !== undefined ? options.isActive : null,
        limit: pagination.limit,
        offset: pagination.offset,
        orderBy: orderBy.length > 0 ? orderBy : [{ column: 'created_at', direction: 'desc' }]
      };

      // 获取用户列表和总数
      const [users, total] = await Promise.all([
        userRepo.findMany({}, queryOptions),
        userRepo.count(options.role ? { role: options.role } : {})
      ]);

      return this.buildPaginatedResponse(users, total, pagination);
    }, 'getUserList', { currentUserRole });
  }

  /**
   * 搜索用户
   * @param {string} searchTerm - 搜索关键词
   * @param {string} currentUserRole - 当前用户角色
   * @param {Object} options - 搜索选项
   * @returns {Promise<Object>} 搜索结果
   */
  async searchUsers(searchTerm, currentUserRole, options = {}) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ searchTerm, currentUserRole }, ['searchTerm', 'currentUserRole']);

      if (currentUserRole !== 'admin') {
        throw this.createBusinessError('无权搜索用户', 'ACCESS_DENIED', 403);
      }

      if (searchTerm.length < 2) {
        throw this.createBusinessError('搜索关键词至少需要2个字符');
      }

      // 标准化分页参数
      const pagination = this.normalizePaginationParams(options);

      // 构建搜索选项
      const searchOptions = {
        role: options.role || null,
        isActive: options.isActive !== undefined ? options.isActive : null,
        limit: pagination.limit,
        offset: pagination.offset
      };

      const users = await userRepo.searchUsers(searchTerm, searchOptions);

      return this.buildResponse(users, '搜索完成', {
        searchTerm,
        resultCount: users.length
      });
    }, 'searchUsers', { searchTerm, currentUserRole });
  }

  /**
   * 激活/禁用用户（管理员功能）
   * @param {string} userId - 用户ID
   * @param {boolean} isActive - 是否激活
   * @param {string} currentUserRole - 当前用户角色
   * @returns {Promise<Object>} 更新结果
   */
  async setUserActive(userId, isActive, currentUserRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ userId, currentUserRole }, ['userId', 'currentUserRole']);
      this.validateParamTypes({ isActive }, { isActive: 'boolean' });

      if (currentUserRole !== 'admin') {
        throw this.createBusinessError('无权修改用户状态', 'ACCESS_DENIED', 403);
      }

      const user = await userRepo.findById(userId);
      if (!user) {
        throw this.createBusinessError('用户不存在', 'USER_NOT_FOUND', 404);
      }

      const updatedUser = await userRepo.setUserActive(userId, isActive);

      this.logOperation('user_status_changed', {
        userId,
        email: user.email,
        isActive,
        changedBy: currentUserRole
      });

      return this.buildResponse(updatedUser, `用户${isActive ? '激活' : '禁用'}成功`);
    }, 'setUserActive', { userId, isActive });
  }

  /**
   * 获取用户统计信息
   * @param {string} currentUserRole - 当前用户角色
   * @returns {Promise<Object>} 统计信息
   */
  async getUserStats(currentUserRole) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ currentUserRole }, ['currentUserRole']);

      if (currentUserRole !== 'admin') {
        throw this.createBusinessError('无权查看用户统计', 'ACCESS_DENIED', 403);
      }

      const stats = await userRepo.getUserStats();

      return this.buildResponse(stats, '获取用户统计成功');
    }, 'getUserStats', { currentUserRole });
  }

  /**
   * 检查用户密码状态
   * @param {number} userId - 用户ID
   * @returns {Promise<Object>} 密码状态信息
   */
  async checkPasswordStatus(userId) {
    return await this.handleAsyncOperation(async () => {
      const user = await userRepo.findById(userId);
      if (!user) {
        throw this.createBusinessError('用户不存在', 'USER_NOT_FOUND', 404);
      }

      // 检查密码过期状态
      const expiryCheck = passwordPolicy.checkPasswordExpiry(user.password_changed_at);

      // 获取密码历史统计
      const historyStats = await this.passwordHistoryRepo.getPasswordHistoryStats(userId);

      const passwordStatus = {
        isExpired: expiryCheck.isExpired,
        shouldWarn: expiryCheck.shouldWarn,
        daysUntilExpiry: expiryCheck.daysUntilExpiry,
        message: expiryCheck.message,
        forceChange: user.force_password_change || false,
        lastChanged: user.password_changed_at,
        totalChanges: historyStats.total_changes || 0,
        averageChangeInterval: historyStats.average_change_interval_days
      };

      return this.buildResponse(passwordStatus, '密码状态检查完成');
    }, 'checkPasswordStatus', { userId });
  }

  /**
   * 强制用户更改密码
   * @param {number} userId - 用户ID
   * @param {string} adminRole - 管理员角色
   * @returns {Promise<Object>} 操作结果
   */
  async forcePasswordChange(userId, adminRole) {
    return await this.handleAsyncOperation(async () => {
      if (adminRole !== 'admin') {
        throw this.createBusinessError('无权执行此操作', 'ACCESS_DENIED', 403);
      }

      const user = await userRepo.findById(userId);
      if (!user) {
        throw this.createBusinessError('用户不存在', 'USER_NOT_FOUND', 404);
      }

      await userRepo.updateById(userId, {
        force_password_change: true,
        password_expired: true
      });

      this.logOperation('force_password_change', {
        targetUserId: userId,
        targetEmail: user.email,
        adminRole
      });

      return this.buildResponse(null, '已强制用户更改密码');
    }, 'forcePasswordChange', { userId, adminRole });
  }

  /**
   * 生成强密码建议
   * @param {number} length - 密码长度
   * @returns {Promise<Object>} 密码建议
   */
  async generatePasswordSuggestion(length = 16) {
    return await this.handleAsyncOperation(async () => {
      const suggestedPassword = passwordPolicy.generateStrongPassword(length);
      const validation = passwordPolicy.validatePassword(suggestedPassword);

      const suggestion = {
        password: suggestedPassword,
        strength: passwordPolicy.getStrengthDescription(validation.strength),
        score: validation.score,
        tips: [
          '请将此密码保存在安全的地方',
          '不要在多个账户中使用相同的密码',
          '定期更换密码以保持账户安全',
          '避免在公共场所输入密码'
        ]
      };

      return this.buildResponse(suggestion, '密码建议生成成功');
    }, 'generatePasswordSuggestion', { length });
  }

  /**
   * 生成JWT令牌
   * @param {Object} user - 用户对象
   * @returns {string} JWT令牌
   */
  generateToken(user) {
    const payload = {
      id: user.id,
      email: user.email,
      role: user.role
    };

    return jwt.sign(payload, config.jwt.secret, {
      expiresIn: config.jwt.expiresIn
    });
  }

  /**
   * 获取所有用户列表（管理员）
   * @param {Object} options - 查询选项
   * @returns {Promise<Object>} 用户列表
   */
  async getAllUsers(options = {}) {
    return await this.handleAsyncOperation(async () => {
      // 标准化分页参数
      const pagination = this.normalizePaginationParams(options);

      // 构建查询选项
      const queryOptions = {
        limit: pagination.limit,
        offset: pagination.offset,
        search: options.search || null
      };

      // 获取用户列表和总数
      const [users, totalCount] = await Promise.all([
        userRepo.findAll(queryOptions),
        userRepo.countAll(queryOptions)
      ]);

      // 清理敏感信息
      const sanitizedUsers = users.map(user => this.sanitizeData(user));

      return this.buildPaginatedResponse(sanitizedUsers, totalCount, pagination);
    }, 'getAllUsers', { options });
  }

  /**
   * 更新用户状态（管理员）
   * @param {string} userId - 用户ID
   * @param {string} status - 新状态
   * @param {string} adminId - 管理员ID
   * @returns {Promise<Object>} 更新结果
   */
  async updateUserStatus(userId, status, adminId) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ userId, status, adminId }, ['userId', 'status', 'adminId']);

      // 验证状态值
      const validStatuses = ['active', 'inactive', 'suspended'];
      if (!validStatuses.includes(status)) {
        throw this.createBusinessError('无效的用户状态', 'INVALID_STATUS', 400);
      }

      const user = await userRepo.findById(userId);
      if (!user) {
        throw this.createBusinessError('用户不存在', 'USER_NOT_FOUND', 404);
      }

      // 防止管理员修改自己的状态
      if (userId === adminId) {
        throw this.createBusinessError('不能修改自己的状态', 'CANNOT_MODIFY_SELF', 400);
      }

      // 更新用户状态
      const updatedUser = await userRepo.updateById(userId, { status });

      this.logOperation('user_status_updated', {
        userId,
        adminId,
        oldStatus: user.status,
        newStatus: status
      });

      return this.buildResponse(this.sanitizeData(updatedUser), '用户状态更新成功');
    }, 'updateUserStatus', { userId, status, adminId });
  }

  /**
   * 重置用户密码（管理员）
   * @param {string} userId - 用户ID
   * @param {string} adminId - 管理员ID
   * @returns {Promise<Object>} 重置结果
   */
  async resetUserPassword(userId, adminId) {
    return await this.handleAsyncOperation(async () => {
      this.validateRequiredParams({ userId, adminId }, ['userId', 'adminId']);

      const user = await userRepo.findById(userId);
      if (!user) {
        throw this.createBusinessError('用户不存在', 'USER_NOT_FOUND', 404);
      }

      // 防止管理员重置自己的密码
      if (userId === adminId) {
        throw this.createBusinessError('不能重置自己的密码', 'CANNOT_RESET_SELF', 400);
      }

      // 生成临时密码
      const tempPassword = this.generateTempPassword();

      // 更新密码
      const success = await userRepo.updatePassword(userId, tempPassword);
      if (!success) {
        throw this.createBusinessError('密码重置失败', 'PASSWORD_RESET_FAILED', 500);
      }

      this.logOperation('user_password_reset', {
        userId,
        adminId,
        email: user.email
      });

      return this.buildResponse({
        tempPassword,
        message: '密码已重置，请通知用户尽快修改密码'
      }, '密码重置成功');
    }, 'resetUserPassword', { userId, adminId });
  }

  /**
   * 获取用户统计信息（管理员）
   * @returns {Promise<Object>} 统计信息
   */
  async getUserStats() {
    return await this.handleAsyncOperation(async () => {
      const stats = await userRepo.getGlobalStats();

      return this.buildResponse(stats, '获取用户统计成功');
    }, 'getUserStats');
  }

  /**
   * 生成临时密码
   * @returns {string} 临时密码
   */
  generateTempPassword() {
    const chars = 'ABCDEFGHJKMNPQRSTUVWXYZabcdefghijkmnpqrstuvwxyz23456789';
    let password = '';
    for (let i = 0; i < 12; i++) {
      password += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return password;
  }

  /**
   * 验证JWT令牌
   * @param {string} token - JWT令牌
   * @returns {Object} 解码的用户信息
   */
  verifyToken(token) {
    try {
      return jwt.verify(token, config.jwt.secret);
    } catch (error) {
      throw this.createBusinessError('无效的令牌', 'INVALID_TOKEN', 401);
    }
  }

  /**
   * 导出用户数据（管理员功能）
   * @param {Object} filters - 过滤条件
   * @param {string} format - 导出格式 ('csv', 'excel')
   * @returns {Promise<Object>} 导出结果
   */
  async exportUsers(filters = {}, format = 'csv') {
    return await this.handleAsyncOperation(async () => {
      const validFormats = ['csv', 'excel'];
      if (!validFormats.includes(format)) {
        throw this.createBusinessError('不支持的导出格式');
      }

      // 构建查询条件
      const queryOptions = {
        role: filters.role || null,
        isActive: filters.isActive !== undefined ? filters.isActive : null,
        startDate: filters.startDate || null,
        endDate: filters.endDate || null
      };

      // 获取要导出的用户数据
      const users = await userRepo.findForExport(queryOptions);

      // 生成导出文件名
      const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
      const fileName = `users_export_${timestamp}.${format}`;
      const downloadUrl = `/api/downloads/${fileName}`;

      // 导出信息
      const exportInfo = {
        downloadUrl,
        fileName,
        format,
        recordCount: users.length,
        expiresAt: new Date(Date.now() + 3600000).toISOString(), // 1小时后过期
        filters: queryOptions
      };

      this.logOperation('users_export_created', {
        fileName,
        format,
        recordCount: users.length,
        filters: queryOptions
      });

      return this.buildResponse(exportInfo, '用户导出任务已创建');
    }, 'exportUsers', { filters, format });
  }
}

