/**
 * Service层统一导出
 * 提供统一的业务逻辑服务接口
 */

const OrderService = require('./OrderService');
const QuoteService = require('./QuoteService');
const UserService = require('./UserService');
const NotificationService = require('./NotificationService');
const OrderIdService = require('./OrderIdService');
const { logger } = require('../config/logger');

class ServiceFactory {
  constructor() {
    this.services = new Map();
    this.initialized = false;
  }

  /**
   * 初始化所有Service
   */
  initialize() {
    if (this.initialized) {
      return;
    }

    try {
      // 创建Service实例
      this.services.set('order', new OrderService());
      this.services.set('quote', new QuoteService());
      this.services.set('user', new UserService());
      this.services.set('notification', new NotificationService());
      this.services.set('orderId', new OrderIdService());

      this.initialized = true;
      logger.info('Service工厂初始化完成', {
        services: Array.from(this.services.keys())
      });
    } catch (error) {
      logger.error('Service工厂初始化失败', {
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 获取Service实例
   * @param {string} name - Service名称
   * @returns {Object} Service实例
   */
  getService(name) {
    if (!this.initialized) {
      this.initialize();
    }

    const service = this.services.get(name);
    if (!service) {
      throw new Error(`Service '${name}' 不存在`);
    }

    return service;
  }

  /**
   * 获取订单Service
   * @returns {OrderService} 订单Service实例
   */
  get order() {
    return this.getService('order');
  }

  /**
   * 获取报价Service
   * @returns {QuoteService} 报价Service实例
   */
  get quote() {
    return this.getService('quote');
  }

  /**
   * 获取用户Service
   * @returns {UserService} 用户Service实例
   */
  get user() {
    return this.getService('user');
  }

  /**
   * 获取通知Service
   * @returns {NotificationService} 通知Service实例
   */
  get notification() {
    return this.getService('notification');
  }

  /**
   * 获取订单ID Service
   * @returns {OrderIdService} 订单ID Service实例
   */
  get orderId() {
    return this.getService('orderId');
  }

  /**
   * 获取所有Service的健康状态
   * @returns {Promise<Object>} 健康状态信息
   */
  async getHealthStatus() {
    if (!this.initialized) {
      return { status: 'not_initialized' };
    }

    const status = {
      status: 'healthy',
      services: {},
      timestamp: new Date().toISOString()
    };

    for (const [name, service] of this.services) {
      try {
        // 检查Service是否正常工作
        if (typeof service.buildResponse === 'function') {
          service.buildResponse('test', 'health_check');
          status.services[name] = 'healthy';
        } else {
          status.services[name] = 'unknown';
        }
      } catch (error) {
        status.services[name] = 'unhealthy';
        status.status = 'degraded';
        logger.warn(`Service '${name}' 健康检查失败`, {
          error: error.message
        });
      }
    }

    return status;
  }

  /**
   * 重置所有Service（主要用于测试）
   */
  reset() {
    this.services.clear();
    this.initialized = false;
    logger.info('Service工厂已重置');
  }
}

// 创建全局Service工厂实例
const serviceFactory = new ServiceFactory();

// 便捷的导出方式
module.exports = {
  ServiceFactory,
  serviceFactory,

  // 直接导出Service类
  OrderService,
  QuoteService,
  UserService,
  NotificationService,
  OrderIdService,

  // 便捷的访问方式
  get orderService() {
    return serviceFactory.order;
  },

  get quoteService() {
    return serviceFactory.quote;
  },

  get userService() {
    return serviceFactory.user;
  },

  get notificationService() {
    return serviceFactory.notification;
  },

  get orderIdService() {
    return serviceFactory.orderId;
  }
};

/**
 * 异步操作性能优化工具类
 * 提供并发控制、批量处理、缓存等性能优化功能
 */

const { logger } = require('../config/logger');

class AsyncOptimizer {
  /**
   * 并发执行任务，限制并发数量
   * @param {Array} tasks - 任务数组（函数）
   * @param {number} maxConcurrency - 最大并发数
   * @returns {Promise<Array>} 执行结果数组
   */
  static async executeConcurrently(tasks, maxConcurrency = 5) {
    if (!Array.isArray(tasks) || tasks.length === 0) {
      return [];
    }

    const results = [];
    const executing = [];

    for (let i = 0; i < tasks.length; i++) {
      const task = tasks[i];

      const promise = (async () => {
        try {
          const startTime = Date.now();
          const result = await task();
          const duration = Date.now() - startTime;

          logger.debug('并发任务完成', { 
            taskIndex: i, 
            duration: `${duration}ms`,
            success: true 
          });

          return { success: true, result, index: i };
        } catch (error) {
          logger.error('并发任务失败', { 
            taskIndex: i, 
            error: error.message 
          });

          return { success: false, error, index: i };
        }
      })();

      results.push(promise);
      executing.push(promise);

      // 当达到最大并发数时，等待一个任务完成
      if (executing.length >= maxConcurrency) {
        const completed = await Promise.race(executing);
        executing.splice(executing.findIndex(p => p === completed), 1);
      }
    }

    // 等待所有任务完成
    const allResults = await Promise.all(results);

    // 按原始顺序排序结果
    return allResults.sort((a, b) => a.index - b.index);
  }

  /**
   * 批量执行任务，支持失败重试
   * @param {Array} tasks - 任务数组
   * @param {Object} options - 选项
   * @returns {Promise<Object>} 批量执行结果
   */
  static async executeBatch(tasks, options = {}) {
    const {
      maxConcurrency = 5,
      retryAttempts = 3,
      retryDelay = 1000,
      failFast = false,
      timeout = 30000
    } = options;

    const startTime = Date.now();
    const results = [];
    const errors = [];

    try {
      // 为每个任务添加超时和重试机制
      const wrappedTasks = tasks.map((task, index) => async () => {
        let lastError;

        for (let attempt = 1; attempt <= retryAttempts; attempt++) {
          try {
            // 添加超时控制
            const timeoutPromise = new Promise((_, reject) => {
              setTimeout(() => reject(new Error('任务执行超时')), timeout);
            });

            const result = await Promise.race([task(), timeoutPromise]);

            if (attempt > 1) {
              logger.info('任务重试成功', { taskIndex: index, attempt });
            }

            return result;
          } catch (error) {
            lastError = error;

            if (attempt < retryAttempts) {
              const delay = retryDelay * Math.pow(2, attempt - 1); // 指数退避
              logger.warn('任务失败，准备重试', { 
                taskIndex: index, 
                attempt, 
                delay,
                error: error.message 
              });

              await new Promise(resolve => setTimeout(resolve, delay));
            }
          }
        }

        throw lastError;
      });

      // 执行并发任务
      const taskResults = await this.executeConcurrently(wrappedTasks, maxConcurrency);

      // 分离成功和失败的结果
      for (const taskResult of taskResults) {
        if (taskResult.success) {
          results.push(taskResult.result);
        } else {
          errors.push({
            index: taskResult.index,
            error: taskResult.error.message
          });

          // 如果启用快速失败，遇到错误立即抛出
          if (failFast) {
            throw taskResult.error;
          }
        }
      }

      const duration = Date.now() - startTime;

      logger.info('批量任务执行完成', {
        totalTasks: tasks.length,
        successCount: results.length,
        errorCount: errors.length,
        duration: `${duration}ms`,
        maxConcurrency
      });

      return {
        success: true,
        results,
        errors,
        stats: {
          total: tasks.length,
          successful: results.length,
          failed: errors.length,
          duration
        }
      };
    } catch (error) {
      logger.error('批量任务执行失败', { error: error.message });
      throw error;
    }
  }

  /**
   * 并发执行多个不同的异步操作
   * @param {Object} operations - 操作对象 {key: asyncFunction}
   * @returns {Promise<Object>} 结果对象 {key: result}
   */
  static async executeParallel(operations) {
    if (!operations || typeof operations !== 'object') {
      return {};
    }

    const keys = Object.keys(operations);
    if (keys.length === 0) {
      return {};
    }

    try {
      const startTime = Date.now();

      // 并发执行所有操作
      const promises = keys.map(async (key) => {
        try {
          const result = await operations[key]();
          return { key, success: true, result };
        } catch (error) {
          logger.error('并行操作失败', { key, error: error.message });
          return { key, success: false, error };
        }
      });

      const results = await Promise.all(promises);
      const duration = Date.now() - startTime;

      // 构建结果对象
      const resultObj = {};
      const errors = [];

      for (const result of results) {
        if (result.success) {
          resultObj[result.key] = result.result;
        } else {
          errors.push({ key: result.key, error: result.error.message });
        }
      }

      logger.debug('并行操作完成', {
        operationCount: keys.length,
        successCount: Object.keys(resultObj).length,
        errorCount: errors.length,
        duration: `${duration}ms`
      });

      return { data: resultObj, errors };
    } catch (error) {
      logger.error('并行操作执行失败', { error: error.message });
      throw error;
    }
  }

  /**
   * 缓存异步操作结果
   * @param {string} key - 缓存键
   * @param {Function} operation - 异步操作
   * @param {number} ttl - 缓存时间（毫秒）
   * @returns {Promise<any>} 操作结果
   */
  static async withCache(key, operation, ttl = 300000) { // 默认5分钟
    const cache = this.getCache();

    // 检查缓存
    const cached = cache.get(key);
    if (cached && Date.now() - cached.timestamp < ttl) {
      logger.debug('使用缓存结果', { key });
      return cached.data;
    }

    try {
      // 执行操作
      const result = await operation();

      // 存储到缓存
      cache.set(key, {
        data: result,
        timestamp: Date.now()
      });

      logger.debug('缓存操作结果', { key });
      return result;
    } catch (error) {
      logger.error('缓存操作失败', { key, error: error.message });
      throw error;
    }
  }

  /**
   * 获取简单的内存缓存实例
   * @returns {Map} 缓存实例
   */
  static getCache() {
    if (!this._cache) {
      this._cache = new Map();

      // 定期清理过期缓存
      setInterval(() => {
        const now = Date.now();
        let cleanedCount = 0;

        for (const [key, value] of this._cache.entries()) {
          if (now - value.timestamp > 600000) { // 10分钟后清理
            this._cache.delete(key);
            cleanedCount++;
          }
        }

        if (cleanedCount > 0) {
          logger.debug('清理过期缓存', { cleanedCount });
        }
      }, 300000); // 每5分钟清理一次
    }

    return this._cache;
  }

  /**
   * 清空缓存
   */
  static clearCache() {
    if (this._cache) {
      this._cache.clear();
      logger.info('缓存已清空');
    }
  }
}

module.exports = AsyncOptimizer;

/**
 * 数据库索引管理器
 * 优化数据库索引创建的竞态条件问题
 * 使用事务和锁机制确保索引创建的原子性
 */

const { db, transactionManager } = require('../config/database');
const { logger } = require('../config/logger');
const { lockManager, LOCK_KEYS } = require('./LockManager');

class IndexManager {
  constructor() {
    this.indexDefinitions = new Map();
    this.createdIndexes = new Set();
    this.initializeIndexDefinitions();
  }

  /**
   * 初始化索引定义
   */
  initializeIndexDefinitions() {
    // 用户表索引
    this.addIndexDefinition('idx_users_email', {
      table: 'users',
      columns: ['email'],
      unique: true,
      description: '用户邮箱唯一索引，用于登录查询'
    });

    this.addIndexDefinition('idx_users_role', {
      table: 'users',
      columns: ['role'],
      description: '用户角色索引，用于权限查询'
    });

    this.addIndexDefinition('idx_users_active', {
      table: 'users',
      columns: ['isActive'],
      description: '用户状态索引，用于筛选活跃用户'
    });

    // 订单表索引
    this.addIndexDefinition('idx_orders_status', {
      table: 'orders',
      columns: ['status'],
      description: '订单状态索引，用于状态筛选'
    });

    this.addIndexDefinition('idx_orders_created_at', {
      table: 'orders',
      columns: ['createdAt'],
      order: 'DESC',
      description: '订单创建时间索引，用于时间排序'
    });

    this.addIndexDefinition('idx_orders_user_id', {
      table: 'orders',
      columns: ['userId'],
      description: '订单用户ID索引，用于数据隔离'
    });

    this.addIndexDefinition('idx_orders_user_status', {
      table: 'orders',
      columns: ['userId', 'status'],
      description: '订单用户状态复合索引，优化用户订单查询'
    });

    // 报价表索引
    this.addIndexDefinition('idx_quotes_order_id', {
      table: 'quotes',
      columns: ['orderId'],
      description: '报价订单ID索引，用于订单报价查询'
    });

    this.addIndexDefinition('idx_quotes_order_provider', {
      table: 'quotes',
      columns: ['orderId', 'provider'],
      unique: true,
      description: '报价订单供应商复合唯一索引，防止重复报价'
    });

    this.addIndexDefinition('idx_quotes_price', {
      table: 'quotes',
      columns: ['price'],
      description: '报价价格索引，用于价格排序'
    });

    // 物流公司表索引
    this.addIndexDefinition('idx_providers_access_key', {
      table: 'providers',
      columns: ['accessKey'],
      unique: true,
      description: '物流公司访问密钥唯一索引'
    });

    this.addIndexDefinition('idx_providers_active', {
      table: 'providers',
      columns: ['isActive'],
      description: '物流公司状态索引'
    });

    // 序列表索引
    this.addIndexDefinition('idx_order_sequences_date', {
      table: 'order_sequences',
      columns: ['date'],
      unique: true,
      description: '订单序列日期唯一索引'
    });
  }

  /**
   * 添加索引定义
   * @param {string} name - 索引名称
   * @param {Object} definition - 索引定义
   */
  addIndexDefinition(name, definition) {
    this.indexDefinitions.set(name, {
      name,
      ...definition,
      created: false
    });
  }

  /**
   * 创建所有索引
   * @param {Object} options - 选项
   * @returns {Promise<Object>} 创建结果
   */
  async createAllIndexes(options = {}) {
    const { 
      force = false, 
      parallel = false, 
      skipExisting = true 
    } = options;

    const lockKey = 'index_creation_global';

    return await lockManager.withLock(lockKey, async () => {
      const results = {
        created: [],
        skipped: [],
        failed: [],
        total: this.indexDefinitions.size
      };

      logger.info('开始创建数据库索引', { 
        total: results.total, 
        force, 
        parallel 
      });

      if (parallel) {
        // 并行创建（谨慎使用）
        const promises = Array.from(this.indexDefinitions.values()).map(
          indexDef => this.createSingleIndex(indexDef, { force, skipExisting })
            .then(result => ({ ...result, indexName: indexDef.name }))
            .catch(error => ({ 
              success: false, 
              error: error.message, 
              indexName: indexDef.name 
            }))
        );

        const parallelResults = await Promise.all(promises);

        parallelResults.forEach(result => {
          if (result.success) {
            if (result.created) {
              results.created.push(result.indexName);
            } else {
              results.skipped.push(result.indexName);
            }
          } else {
            results.failed.push({ name: result.indexName, error: result.error });
          }
        });
      } else {
        // 串行创建（推荐）
        for (const indexDef of this.indexDefinitions.values()) {
          try {
            const result = await this.createSingleIndex(indexDef, { force, skipExisting });

            if (result.created) {
              results.created.push(indexDef.name);
            } else {
              results.skipped.push(indexDef.name);
            }
          } catch (error) {
            results.failed.push({ name: indexDef.name, error: error.message });
            logger.error('索引创建失败', { 
              indexName: indexDef.name, 
              error: error.message 
            });
          }
        }
      }

      logger.info('索引创建完成', results);
      return results;
    }, {
      timeout: 300000, // 5分钟超时
      maxWait: 10000
    });
  }

  /**
   * 创建单个索引
   * @param {Object} indexDef - 索引定义
   * @param {Object} options - 选项
   * @returns {Promise<Object>} 创建结果
   */
  async createSingleIndex(indexDef, options = {}) {
    const { force = false, skipExisting = true } = options;
    const { name, table, columns, unique = false, order } = indexDef;

    return await transactionManager.executeWithRetry(async (trx) => {
      // 检查索引是否已存在
      if (!force && skipExisting) {
        const exists = await this.indexExists(name, trx);
        if (exists) {
          logger.debug('索引已存在，跳过创建', { indexName: name });
          this.createdIndexes.add(name);
          return { success: true, created: false, exists: true };
        }
      }

      // 检查表是否存在
      const tableExists = await trx.schema.hasTable(table);
      if (!tableExists) {
        throw new Error(`表 ${table} 不存在`);
      }

      // 构建索引创建SQL
      const sql = this.buildIndexSQL(indexDef);

      logger.debug('创建索引', { indexName: name, sql });

      // 执行索引创建
      await trx.raw(sql);

      this.createdIndexes.add(name);

      logger.info('索引创建成功', { 
        indexName: name, 
        table, 
        columns: columns.join(', '),
        unique 
      });

      return { success: true, created: true, exists: false };
    });
  }

  /**
   * 构建索引创建SQL
   * @param {Object} indexDef - 索引定义
   * @returns {string} SQL语句
   */
  buildIndexSQL(indexDef) {
    const { name, table, columns, unique = false, order, where } = indexDef;

    let sql = `CREATE ${unique ? 'UNIQUE ' : ''}INDEX IF NOT EXISTS ${name} ON ${table}`;

    // 添加列定义
    const columnDefs = columns.map(col => {
      if (typeof col === 'string') {
        return order ? `${col} ${order}` : col;
      }
      return col;
    });

    sql += ` (${columnDefs.join(', ')})`;

    // 添加WHERE条件（部分索引）
    if (where) {
      sql += ` WHERE ${where}`;
    }

    return sql;
  }

  /**
   * 检查索引是否存在
   * @param {string} indexName - 索引名称
   * @param {Object} trx - 事务对象
   * @returns {Promise<boolean>} 是否存在
   */
  async indexExists(indexName, trx = db) {
    try {
      const result = await trx.raw(`
        SELECT name FROM sqlite_master 
        WHERE type = 'index' AND name = ?
      `, [indexName]);

      return result && result.length > 0;
    } catch (error) {
      logger.error('检查索引存在性失败', { indexName, error: error.message });
      return false;
    }
  }

  /**
   * 删除索引
   * @param {string} indexName - 索引名称
   * @returns {Promise<boolean>} 是否成功
   */
  async dropIndex(indexName) {
    const lockKey = `index_drop_${indexName}`;

    return await lockManager.withLock(lockKey, async () => {
      try {
        await db.raw(`DROP INDEX IF EXISTS ${indexName}`);
        this.createdIndexes.delete(indexName);

        logger.info('索引删除成功', { indexName });
        return true;
      } catch (error) {
        logger.error('索引删除失败', { indexName, error: error.message });
        return false;
      }
    });
  }

  /**
   * 重建索引
   * @param {string} indexName - 索引名称
   * @returns {Promise<boolean>} 是否成功
   */
  async rebuildIndex(indexName) {
    const indexDef = this.indexDefinitions.get(indexName);
    if (!indexDef) {
      throw new Error(`未找到索引定义: ${indexName}`);
    }

    const lockKey = `index_rebuild_${indexName}`;

    return await lockManager.withLock(lockKey, async () => {
      try {
        // 先删除再创建
        await this.dropIndex(indexName);
        const result = await this.createSingleIndex(indexDef, { force: true });

        logger.info('索引重建成功', { indexName });
        return result.success;
      } catch (error) {
        logger.error('索引重建失败', { indexName, error: error.message });
        return false;
      }
    });
  }

  /**
   * 获取索引统计信息
   * @returns {Promise<Object>} 统计信息
   */
  async getIndexStats() {
    try {
      const allIndexes = await db.raw(`
        SELECT name, tbl_name, sql 
        FROM sqlite_master 
        WHERE type = 'index' AND name NOT LIKE 'sqlite_%'
        ORDER BY name
      `);

      const stats = {
        total: allIndexes.length,
        defined: this.indexDefinitions.size,
        created: this.createdIndexes.size,
        indexes: allIndexes.map(idx => ({
          name: idx.name,
          table: idx.tbl_name,
          sql: idx.sql,
          managed: this.indexDefinitions.has(idx.name)
        }))
      };

      return stats;
    } catch (error) {
      logger.error('获取索引统计信息失败', { error: error.message });
      throw error;
    }
  }

  /**
   * 验证索引完整性
   * @returns {Promise<Object>} 验证结果
   */
  async validateIndexes() {
    const results = {
      valid: [],
      invalid: [],
      missing: []
    };

    for (const [name, indexDef] of this.indexDefinitions) {
      try {
        const exists = await this.indexExists(name);

        if (exists) {
          // 可以添加更多验证逻辑，比如检查索引结构
          results.valid.push(name);
        } else {
          results.missing.push(name);
        }
      } catch (error) {
        results.invalid.push({ name, error: error.message });
      }
    }

    logger.info('索引验证完成', {
      valid: results.valid.length,
      invalid: results.invalid.length,
      missing: results.missing.length
    });

    return results;
  }
}

// 创建全局索引管理器实例
