  sleep: (ms) => new Promise(resolve => setTimeout(resolve, ms)),

  // 重试函数
  retry: async (fn, retries = 3, delay = 1000) => {
    for (let i = 0; i < retries; i++) {
      try {
        return await fn();
      } catch (error) {
        if (i === retries - 1) throw error;
        await utils.sleep(delay);
      }
    }
  },

  // 生成随机字符串
