      providerRepo.validateAccess.mockResolvedValue(mockProvider);

      await expect(
        quoteService.createOrUpdateQuote(orderId, provider, validQuoteData, accessKey)
      ).rejects.toThrow('供应商名称与访问密钥不匹配');
